SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "An electric dipole placed in a uniform electric field experiences:", "explanation": "In a uniform field, both charges of the dipole experience equal and opposite forces (F = qE). These form a couple (torque) but have zero net force. The torque aligns the dipole with the field. There is no translational motion — only rotation.", "correct_answer": "C", "concept_tags": ["dipole-in-uniform-field", "torque", "zero-net-force"], "payload": {"question_id": "cuet-phy-elec-dipole-03", "subtopic": "Dipole in uniform field", "topic_name": "Electric Dipole", "bloom_level": "understand", "options": [{"key": "A", "text": "A net force but no torque", "is_correct": false}, {"key": "B", "text": "Both a net force and a net torque", "is_correct": false}, {"key": "C", "text": "A net torque but no net force", "is_correct": true}, {"key": "D", "text": "Neither force nor torque", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "In a uniform field, forces on +q and −q are equal in magnitude but opposite — they cancel. Net force is zero.", "misconception": "Not recognising force cancellation in uniform fields"}, {"option_key": "B", "hint": "Net force is zero in a uniform field. Both force AND torque occur only in a non-uniform field.", "misconception": "Confusing uniform field with non-uniform field"}, {"option_key": "D", "hint": "The equal and opposite forces act at different points, creating a torque (couple). Torque is definitely non-zero unless the dipole is aligned.", "misconception": "Thinking zero net force means zero torque"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric field on the equatorial line of a dipole at large distance r varies as:", "explanation": "At a point on the equatorial (perpendicular bisector) line at large distance r, the electric field of a dipole is E_eq = kp/r³, where p is the dipole moment. The field decreases as the inverse cube of distance — faster than a point charge (1/r²).", "correct_answer": "D", "concept_tags": ["equatorial-field", "inverse-cube", "dipole"], "payload": {"question_id": "cuet-phy-elec-dipole-04", "subtopic": "Dipole field expressions", "topic_name": "Electric Dipole", "bloom_level": "remember", "options": [{"key": "A", "text": "1/r", "is_correct": false}, {"key": "B", "text": "1/r²", "is_correct": false}, {"key": "C", "text": "1/r⁴", "is_correct": false}, {"key": "D", "text": "1/r³", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1/r dependence is for an infinite line charge, not a dipole.", "misconception": "Confusing dipole with line charge"}, {"option_key": "B", "hint": "1/r² is the field of a point charge (monopole). A dipole''s field falls off faster because the +q and −q fields partially cancel.", "misconception": "Using point charge dependence for a dipole"}, {"option_key": "C", "hint": "1/r⁴ is the field of a quadrupole, not a dipole.", "misconception": "Confusing dipole with quadrupole"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "An electric dipole consists of two equal and opposite charges separated by a small distance d. The electric dipole moment is defined as:", "explanation": "The electric dipole moment p is defined as the product of either charge magnitude q and the separation distance d, i.e., p = qd. It is a vector quantity directed from the negative charge to the positive charge.", "correct_answer": "B", "concept_tags": ["electric-dipole-moment", "dipole-definition", "vector-quantity"], "payload": {"question_id": "cuet-phy-elec-dipole-05", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "remember", "options": [{"key": "A", "text": "p = q/d", "is_correct": false}, {"key": "B", "text": "p = qd", "is_correct": true}, {"key": "C", "text": "p = q²d", "is_correct": false}, {"key": "D", "text": "p = qd²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Dividing charge by distance does not give dipole moment. The dipole moment is the product q × d, not q/d.", "misconception": "Confusing the formula as a ratio rather than a product"}, {"option_key": "C", "hint": "The dipole moment involves q to the first power, not q². The q² appears in Coulomb''s force formula, not in dipole moment.", "misconception": "Mixing up dipole moment with Coulomb''s law terms"}, {"option_key": "D", "hint": "The distance d appears to the first power in the dipole moment, not d². The formula is simply p = qd.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of electric dipole moment is:", "explanation": "Since dipole moment p = qd, its SI unit is the product of the units of charge (coulomb) and distance (metre), which gives C·m (coulomb-metre).", "correct_answer": "A", "concept_tags": ["dipole-moment", "SI-units", "coulomb-metre"], "payload": {"question_id": "cuet-phy-elec-dipole-06", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "remember", "options": [{"key": "A", "text": "C·m", "is_correct": true}, {"key": "B", "text": "C/m", "is_correct": false}, {"key": "C", "text": "C·m²", "is_correct": false}, {"key": "D", "text": "C/m²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "C/m would be units of charge per unit length (linear charge density), not dipole moment.", "misconception": "Confusing dipole moment units with linear charge density"}, {"option_key": "C", "hint": "C·m² has an extra factor of length; the dipole moment is q times d (first power), not d².", "misconception": "Confusing with quadrupole moment units"}, {"option_key": "D", "hint": "C/m² is the unit of surface charge density, not dipole moment.", "misconception": "Confusing with surface charge density units"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The torque on an electric dipole of moment p = 3 × 10⁻²⁹ C·m placed in a uniform electric field E = 10⁵ N/C at 30° to the field is:", "explanation": "Torque τ = pE sinθ = 3 × 10⁻²⁹ × 10⁵ × sin30° = 3 × 10⁻²⁴ × 0.5 = 1.5 × 10⁻²⁴ N·m.", "correct_answer": "C", "concept_tags": ["dipole-torque", "numerical", "sine-formula"], "payload": {"question_id": "cuet-phy-elec-dipole-07", "subtopic": "Torque on dipole", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "3 × 10⁻²⁴ N·m", "is_correct": false}, {"key": "B", "text": "2.6 × 10⁻²⁴ N·m", "is_correct": false}, {"key": "C", "text": "1.5 × 10⁻²⁴ N·m", "is_correct": true}, {"key": "D", "text": "6 × 10⁻²⁴ N·m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3 × 10⁻²⁴ is pE without the sinθ factor. You must multiply by sin30° = 0.5.", "misconception": "Forgetting the sine factor in torque formula"}, {"option_key": "B", "hint": "2.6 × 10⁻²⁴ would come from using sin30° ≈ 0.866, which is actually sin60°.", "misconception": "Confusing sin30° with sin60°"}, {"option_key": "D", "hint": "6 × 10⁻²⁴ is double pE — there''s no factor of 2 in the torque formula.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The work done in rotating an electric dipole from angle θ₁ to θ₂ in a uniform electric field E is:", "explanation": "The potential energy of a dipole in a field is U = −pE cosθ. Work done = ΔU = U₂ − U₁ = −pE cosθ₂ − (−pE cosθ₁) = pE(cosθ₁ − cosθ₂). This is positive when the dipole rotates away from the field direction.", "correct_answer": "A", "concept_tags": ["work-done", "dipole-rotation", "potential-energy"], "payload": {"question_id": "cuet-phy-elec-dipole-08", "subtopic": "Energy of dipole in field", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "pE(cosθ₁ − cosθ₂)", "is_correct": true}, {"key": "B", "text": "pE(cosθ₂ − cosθ₁)", "is_correct": false}, {"key": "C", "text": "pE(sinθ₁ − sinθ₂)", "is_correct": false}, {"key": "D", "text": "pE(θ₂ − θ₁)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This has the sign reversed. W = U_final − U_initial = (−pEcosθ₂) − (−pEcosθ₁) = pE(cosθ₁ − cosθ₂).", "misconception": "Reversing the sign of work done"}, {"option_key": "C", "hint": "The potential energy involves cosine (U = −pEcosθ), not sine. Sine appears in the torque formula.", "misconception": "Confusing torque formula (sinθ) with energy formula (cosθ)"}, {"option_key": "D", "hint": "Work is not simply pE × angle difference. The integration of τ dθ = pE sinθ dθ gives cosines, not linear angle.", "misconception": "Assuming linear relationship between work and angle"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The potential energy of an electric dipole is minimum when the angle between p and E is:", "explanation": "Potential energy U = −pE cosθ. This is minimum (most negative) when cosθ is maximum, i.e., cosθ = 1 → θ = 0°. At this angle, the dipole is aligned with the field (stable equilibrium). The energy is U_min = −pE.", "correct_answer": "B", "concept_tags": ["stable-equilibrium", "minimum-energy", "alignment"], "payload": {"question_id": "cuet-phy-elec-dipole-09", "subtopic": "Dipole equilibrium", "topic_name": "Electric Dipole", "bloom_level": "understand", "options": [{"key": "A", "text": "180°", "is_correct": false}, {"key": "B", "text": "0°", "is_correct": true}, {"key": "C", "text": "90°", "is_correct": false}, {"key": "D", "text": "45°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "At 180°, U = −pE cos180° = +pE, which is the maximum energy (unstable equilibrium), not minimum.", "misconception": "Confusing maximum energy with minimum energy"}, {"option_key": "C", "hint": "At 90°, U = −pE cos90° = 0, which is between the minimum (−pE) and maximum (+pE).", "misconception": "Thinking zero energy means minimum energy"}, {"option_key": "D", "hint": "At 45°, U = −pE cos45° = −pE/√2, which is negative but not the most negative value.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field at a point on the axial line of a short dipole at distance r (r >> 2a) from the centre is E_a, and on the equatorial line at the same distance is E_e. The angle between E_a and E_e is:", "explanation": "On the axial line, the field points along the dipole moment (from −q to +q direction, same as p). On the equatorial line, the field points antiparallel to the dipole moment (opposite to p). Therefore, E_a is along p and E_e is opposite to p, making the angle between them 180°.", "correct_answer": "D", "concept_tags": ["axial-field", "equatorial-field", "direction-comparison"], "payload": {"question_id": "cuet-phy-elec-dipole-10", "subtopic": "Dipole field directions", "topic_name": "Electric Dipole", "bloom_level": "analyze", "options": [{"key": "A", "text": "0°", "is_correct": false}, {"key": "B", "text": "90°", "is_correct": false}, {"key": "C", "text": "120°", "is_correct": false}, {"key": "D", "text": "180°", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0° would mean both fields point in the same direction, but on the equatorial line the field is antiparallel to p, while on the axial line it''s parallel to p.", "misconception": "Not distinguishing axial and equatorial field directions"}, {"option_key": "B", "hint": "90° would mean the fields are perpendicular. The axial and equatorial fields are both along the dipole axis but in opposite directions.", "misconception": "Confusing the observation point geometry with the field direction"}, {"option_key": "C", "hint": "120° has no special significance for dipole field directions. The angle is exactly 180°.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electric dipole is placed at the centre of a sphere. The total electric flux through the sphere is:", "explanation": "By Gauss''s law, total flux Φ = q_enc/ε₀. An electric dipole has total charge = +q + (−q) = 0. Therefore, the total flux through any closed surface enclosing the dipole is zero, regardless of the surface shape.", "correct_answer": "A", "concept_tags": ["gauss-law", "dipole-flux", "zero-enclosed-charge"], "payload": {"question_id": "cuet-phy-elec-dipole-11", "subtopic": "Flux due to a dipole", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "q/ε₀", "is_correct": false}, {"key": "C", "text": "2q/ε₀", "is_correct": false}, {"key": "D", "text": "p/ε₀", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "q/ε₀ would be the flux from a single charge q. The dipole has both +q and −q, giving total enclosed charge = 0.", "misconception": "Counting only the positive charge of the dipole"}, {"option_key": "C", "hint": "2q/ε₀ adds the magnitudes of both charges. Gauss''s law uses algebraic (signed) sum: +q + (−q) = 0.", "misconception": "Adding absolute values instead of algebraic sum"}, {"option_key": "D", "hint": "The dipole moment p does not appear in Gauss''s law. Flux depends on enclosed charge, not dipole moment.", "misconception": "Confusing dipole moment with charge in Gauss''s law"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The work done in rotating a dipole from stable equilibrium (θ = 0°) to unstable equilibrium (θ = 180°) in a uniform field E is:", "explanation": "W = pE(cosθ₁ − cosθ₂) = pE(cos0° − cos180°) = pE(1 − (−1)) = 2pE. This is the maximum work that can be done on the dipole in a given field.", "correct_answer": "C", "concept_tags": ["work-done", "stable-unstable", "dipole-rotation"], "payload": {"question_id": "cuet-phy-elec-dipole-12", "subtopic": "Energy of dipole in field", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "pE", "is_correct": false}, {"key": "B", "text": "pE/2", "is_correct": false}, {"key": "C", "text": "2pE", "is_correct": true}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "pE would be the work for 0° → 90° (cos0° − cos90° = 1 − 0 = 1). For 0° → 180°, the factor is 2.", "misconception": "Calculating work for half rotation instead of full 180°"}, {"option_key": "B", "hint": "pE/2 has no physical basis here. The cosine difference is cos0° − cos180° = 2.", "misconception": null}, {"option_key": "D", "hint": "Zero work would mean the initial and final energies are equal. But U(0°) = −pE and U(180°) = +pE, differing by 2pE.", "misconception": "Thinking rotation between equilibrium positions requires no work"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The torque experienced by an electric dipole of moment p placed in a uniform electric field E at an angle θ to the field is:", "explanation": "The torque on a dipole in a uniform electric field is given by τ = p × E, and its magnitude is τ = pE sinθ. The torque is maximum when θ = 90° (dipole perpendicular to the field) and zero when θ = 0° or 180° (dipole parallel or anti-parallel to the field).", "correct_answer": "B", "concept_tags": ["torque-on-dipole", "uniform-field", "cross-product"], "payload": {"question_id": "cuet-phy-elec-dipole-13", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "pE cosθ", "is_correct": false}, {"key": "B", "text": "pE sinθ", "is_correct": true}, {"key": "C", "text": "pE tanθ", "is_correct": false}, {"key": "D", "text": "pE/sinθ", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "pE cosθ gives the component along the field, which is not the torque. Torque involves the perpendicular component (sinθ), like the cross product.", "misconception": "Confusing torque formula (sinθ) with potential energy formula (cosθ)"}, {"option_key": "C", "hint": "The tanθ function does not appear in the torque expression. The torque is the magnitude of the cross product p × E = pE sinθ.", "misconception": null}, {"option_key": "D", "hint": "Dividing by sinθ would make the torque infinite at θ = 0°, which is unphysical since the torque should be zero when aligned.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The potential energy of an electric dipole of moment p in a uniform electric field E, when the dipole makes an angle θ with the field, is:", "explanation": "The potential energy of a dipole in a uniform field is U = −p·E = −pE cosθ. This expression shows that U is minimum (most stable) when θ = 0° (dipole aligned with field) and maximum when θ = 180° (dipole anti-parallel to field).", "correct_answer": "C", "concept_tags": ["dipole-potential-energy", "uniform-field", "stable-equilibrium"], "payload": {"question_id": "cuet-phy-elec-dipole-14", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "pE cosθ", "is_correct": false}, {"key": "B", "text": "pE sinθ", "is_correct": false}, {"key": "C", "text": "−pE cosθ", "is_correct": true}, {"key": "D", "text": "−pE sinθ", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The correct expression has a negative sign. Without the negative sign, the energy would be maximum at θ = 0°, which contradicts the stable equilibrium at θ = 0°.", "misconception": "Forgetting the negative sign in the potential energy expression"}, {"option_key": "B", "hint": "pE sinθ is the expression for torque magnitude, not potential energy. Potential energy uses the dot product (cosθ), not the cross product (sinθ).", "misconception": "Confusing torque with potential energy"}, {"option_key": "D", "hint": "The potential energy involves cosθ (from the dot product p·E), not sinθ. The sinθ function appears in the torque expression.", "misconception": "Mixing up sinθ and cosθ in dipole expressions"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electric dipole is placed in a uniform electric field. The net force on the dipole is:", "explanation": "In a uniform electric field, the force on the positive charge (+qE) and the force on the negative charge (−qE) are equal in magnitude but opposite in direction. Hence, the net force is zero. However, a net torque acts on the dipole unless it is aligned with the field.", "correct_answer": "A", "concept_tags": ["dipole-in-uniform-field", "net-force", "torque"], "payload": {"question_id": "cuet-phy-elec-dipole-15", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "understand", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "qE in the direction of the field", "is_correct": false}, {"key": "C", "text": "2qE in the direction of the field", "is_correct": false}, {"key": "D", "text": "qE perpendicular to the field", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "In a uniform field, the positive charge experiences +qE and the negative charge experiences −qE. These cancel, giving zero net force.", "misconception": "Considering only the force on the positive charge"}, {"option_key": "C", "hint": "2qE would be the sum of magnitudes if both forces were in the same direction, but they are opposite, so they cancel.", "misconception": "Adding force magnitudes instead of vector addition"}, {"option_key": "D", "hint": "There is no perpendicular net force component. The forces on both charges are along the field direction, and they cancel out.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two electric field lines:", "explanation": "Electric field lines never cross each other. If they did, it would imply two different directions of the electric field at the point of intersection, which is physically impossible since the electric field at any point has a unique direction.", "correct_answer": "D", "concept_tags": ["field-line-properties", "uniqueness-of-field", "electric-field-lines"], "payload": {"question_id": "cuet-phy-elec-dipole-16", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "understand", "options": [{"key": "A", "text": "Can cross each other at any point", "is_correct": false}, {"key": "B", "text": "Cross only at the location of a charge", "is_correct": false}, {"key": "C", "text": "Cross only in a non-uniform field", "is_correct": false}, {"key": "D", "text": "Never cross each other", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "If field lines crossed, there would be two directions of the field at the crossing point, which contradicts the uniqueness of the electric field vector.", "misconception": "Not understanding the uniqueness of the electric field direction"}, {"option_key": "B", "hint": "Field lines do not cross even at charge locations. At a point charge, lines either diverge outward or converge inward, but they don''t intersect.", "misconception": "Confusing convergence/divergence with crossing"}, {"option_key": "C", "hint": "Field lines never cross regardless of whether the field is uniform or non-uniform. The uniqueness of the field direction applies everywhere.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "At a general point at distance r (r >> 2a) from a short dipole, the electric field makes an angle α with the position vector r. If the point makes angle θ with the dipole axis, then tanα equals:", "explanation": "The general field of a dipole at angle θ has radial component E_r = 2kp cosθ/r³ and transverse component E_θ = kp sinθ/r³. The angle α between E and r satisfies tanα = E_θ/E_r = (sinθ)/(2cosθ) = (1/2)tanθ. This is a standard and important result.", "correct_answer": "B", "concept_tags": ["general-dipole-field", "field-angle", "tangent-relation"], "payload": {"question_id": "cuet-phy-elec-dipole-17", "subtopic": "Field at a general point", "topic_name": "Electric Dipole", "bloom_level": "analyze", "options": [{"key": "A", "text": "tanθ", "is_correct": false}, {"key": "B", "text": "(1/2)tanθ", "is_correct": true}, {"key": "C", "text": "2tanθ", "is_correct": false}, {"key": "D", "text": "sinθ/cosθ", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "tanα = tanθ would mean α = θ, i.e., the field is always perpendicular to the dipole axis. This is not true in general.", "misconception": "Assuming the field direction equals the position angle"}, {"option_key": "C", "hint": "2tanθ inverts the factor of 1/2. The ratio E_θ/E_r = sinθ/(2cosθ) = (1/2)tanθ, not 2tanθ.", "misconception": "Inverting the radial and transverse components"}, {"option_key": "D", "hint": "sinθ/cosθ = tanθ, which is the same as option A. The factor of 1/2 from the 2cosθ in the denominator is essential.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field at a general point (r, θ) from a short dipole of moment p has magnitude:", "explanation": "The general field magnitude is E = (kp/r³)√(1 + 3cos²θ). This is derived from E = √(E_r² + E_θ²) where E_r = 2kpcosθ/r³ and E_θ = kpsinθ/r³. So E² = (kp/r³)²(4cos²θ + sin²θ) = (kp/r³)²(3cos²θ + 1).", "correct_answer": "D", "concept_tags": ["general-field-magnitude", "dipole-field", "vector-components"], "payload": {"question_id": "cuet-phy-elec-dipole-18", "subtopic": "Field at a general point", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "kp/r³", "is_correct": false}, {"key": "B", "text": "2kp/r³", "is_correct": false}, {"key": "C", "text": "(kp/r³)√(1 + cos²θ)", "is_correct": false}, {"key": "D", "text": "(kp/r³)√(1 + 3cos²θ)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "kp/r³ is the field on the equatorial line (θ = 90°), where √(1 + 3cos²90°) = 1. It''s not the general formula.", "misconception": "Using the equatorial field value for all angles"}, {"option_key": "B", "hint": "2kp/r³ is the field on the axial line (θ = 0°), where √(1 + 3cos²0°) = 2. It''s not the general formula.", "misconception": "Using the axial field value for all angles"}, {"option_key": "C", "hint": "The coefficient inside the square root should be 3, not 1. It comes from E_r = 2kpcosθ/r³, giving 4cos²θ + sin²θ = 1 + 3cos²θ.", "misconception": "Error in squaring the radial component"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An electric dipole is placed in a non-uniform electric field. The dipole will experience:", "explanation": "In a non-uniform electric field, the forces on the positive and negative charges of the dipole are unequal because the field strength differs at the two charge locations. This results in both a net force (translational motion) and a net torque (rotational tendency). In contrast, a uniform field produces only torque and no net force.", "correct_answer": "C", "concept_tags": ["non-uniform-field", "dipole-force", "dipole-torque"], "payload": {"question_id": "cuet-phy-elec-dipole-19", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "analyze", "options": [{"key": "A", "text": "Only a torque but no net force", "is_correct": false}, {"key": "B", "text": "Only a net force but no torque", "is_correct": false}, {"key": "C", "text": "Both a net force and a torque", "is_correct": true}, {"key": "D", "text": "Neither a net force nor a torque", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This describes a dipole in a uniform field. In a non-uniform field, the unequal forces on the two charges produce a net force in addition to the torque.", "misconception": "Confusing behaviour in uniform and non-uniform fields"}, {"option_key": "B", "hint": "A torque also acts unless the dipole is aligned with the field. In general, a non-uniform field produces both net force and torque.", "misconception": "Ignoring the torque component in a non-uniform field"}, {"option_key": "D", "hint": "A dipole in any electric field (uniform or non-uniform) experiences at least a torque (unless already aligned). A non-uniform field additionally provides a net force.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An electric dipole is initially aligned antiparallel to a uniform electric field E. The work done by the electric field in rotating the dipole to stable equilibrium is:", "explanation": "At antiparallel position (θ = 180°), U_i = −pE cos180° = +pE. At stable equilibrium (θ = 0°), U_f = −pE cos0° = −pE. Work done by the field = −(U_f − U_i) = −(−pE − pE) = 2pE. Alternatively, W_field = −ΔU = 2pE. The field does positive work as it rotates the dipole to the lower energy state.", "correct_answer": "D", "concept_tags": ["work-done-by-field", "dipole-rotation", "antiparallel-alignment"], "payload": {"question_id": "cuet-phy-elec-dipole-20", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "analyze", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "pE", "is_correct": false}, {"key": "C", "text": "−2pE", "is_correct": false}, {"key": "D", "text": "2pE", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The work is not zero because the potential energy changes from +pE to −pE, a change of 2pE.", "misconception": "Thinking no work is done when returning to equilibrium"}, {"option_key": "B", "hint": "pE accounts for rotation from 0° to 90° only. Rotation from 180° to 0° spans a potential energy change of 2pE, not pE.", "misconception": "Computing only half the energy change"}, {"option_key": "C", "hint": "The work done by the field is positive (not negative) because the field drives the dipole toward stable equilibrium, lowering the potential energy.", "misconception": "Confusing work done by external agent with work done by the field"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The electric field of a dipole decreases faster with distance than that of a point charge.\nReason (R): The dipole field varies as 1/r³ while the point charge field varies as 1/r².", "explanation": "Both A and R are correct, and R correctly explains A. The dipole field (1/r³) decreases faster than the monopole field (1/r²) because at large distances, the fields of the +q and −q charges of the dipole nearly cancel, leaving only a residual field that falls off more steeply.", "correct_answer": "A", "concept_tags": ["dipole-vs-monopole", "distance-dependence"], "payload": {"question_id": "cuet-phy-elec-dipole-25", "subtopic": "Dipole field comparison", "topic_name": "Electric Dipole", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R states exactly the quantitative comparison (1/r³ vs 1/r²) that demonstrates A. It is the direct explanation.", "misconception": "Not connecting the power law difference with the rate of decrease"}, {"option_key": "C", "hint": "R is factually correct — dipole field is 1/r³ and point charge is 1/r². These are standard results.", "misconception": null}, {"option_key": "D", "hint": "A is correct — 1/r³ does decrease faster than 1/r² as r increases.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Electric field lines never form closed loops in electrostatics.\nReason (R): Electric field lines originate from positive charges and terminate on negative charges.", "explanation": "The assertion is correct: electrostatic field lines do not form closed loops because the electrostatic field is conservative (work done around a closed path is zero). The reason is also correct and directly explains why: since field lines start at positive charges and end at negative charges, they have definite starting and ending points and cannot form closed loops.", "correct_answer": "A", "concept_tags": ["field-line-properties", "conservative-field", "closed-loops"], "payload": {"question_id": "cuet-phy-elec-dipole-26", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion: the fact that field lines start on positive and end on negative charges is precisely why they cannot form closed loops.", "misconception": "Failing to connect the origin/termination of lines with the no-loop property"}, {"option_key": "C", "hint": "The reason is a correct factual statement about electrostatic field lines.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct; electrostatic field lines indeed do not form closed loops. Closed loops occur only for magnetic field lines or induced electric fields.", "misconception": "Confusing electrostatic and electromagnetic field lines"}]}}]'::jsonb, 'deploy-2026-03-05-b04');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): When an electric dipole is placed in a non-uniform electric field, it experiences a net translational force in addition to torque.\nReason (R): In a non-uniform field, the magnitudes of forces on the two charges of the dipole are different.", "explanation": "Both A and R are correct, and R correctly explains A. In a non-uniform field, E is different at the positions of +q and −q. So F₊ = qE₊ and F₋ = qE₋ differ in magnitude, producing a net force (F₊ − F₋ ≠ 0) in addition to the torque. The dipole moves toward the region of stronger field.", "correct_answer": "A", "concept_tags": ["non-uniform-field", "net-force", "unequal-forces"], "payload": {"question_id": "cuet-phy-elec-dipole-27", "subtopic": "Dipole in non-uniform field", "topic_name": "Electric Dipole", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R is precisely the reason why a net force exists — unequal forces on the two charges directly cause the translational force in A.", "misconception": "Not seeing the direct causal link"}, {"option_key": "C", "hint": "R is correct — in a non-uniform field, E varies with position, so the forces on charges at different positions are different.", "misconception": null}, {"option_key": "D", "hint": "A is correct — a dipole in a non-uniform field experiences both torque and translational force.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The electric field at the equatorial point of a dipole is antiparallel to the dipole moment.\nReason (R): At the equatorial point, the components of the fields due to the two charges along the dipole axis add up while the perpendicular components cancel.", "explanation": "The assertion is correct: at any equatorial point, the net electric field points in the direction opposite to the dipole moment (i.e., from positive to negative charge direction, while p points from negative to positive). The reason is also correct and correctly explains the assertion: at the equatorial point, the perpendicular components of the fields from +q and −q cancel by symmetry, while the axial components both point opposite to p and add up.", "correct_answer": "A", "concept_tags": ["equatorial-field", "dipole-field-direction", "superposition"], "payload": {"question_id": "cuet-phy-elec-dipole-28", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason explains exactly how the field components combine at the equatorial point to produce a field antiparallel to p, so it is the correct explanation.", "misconception": "Not recognizing the causal connection between component analysis and resultant field direction"}, {"option_key": "C", "hint": "The reason accurately describes the superposition of fields at the equatorial point; perpendicular components do cancel and axial components do add.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct; this can be verified by drawing the field vectors from both charges at any equatorial point.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the orientation of a dipole in a uniform electric field (Column I) with the corresponding physical quantity value (Column II):\n\nColumn I:\nA. θ = 0° (parallel to E)\nB. θ = 90° (perpendicular to E)\nC. θ = 180° (antiparallel to E)\nD. θ = 60°\n\nColumn II:\n1. Torque = pE (maximum torque)\n2. Potential energy = −pE (minimum, stable equilibrium)\n3. Potential energy = +pE (maximum, unstable equilibrium)\n4. Torque = (√3/2)pE", "explanation": "At θ = 0°: τ = 0, U = −pE (stable equilibrium) → A-2. At θ = 90°: τ = pE (maximum), U = 0 → B-1. At θ = 180°: τ = 0, U = +pE (unstable equilibrium) → C-3. At θ = 60°: τ = pE sin60° = (√3/2)pE → D-4.", "correct_answer": "B", "concept_tags": ["dipole-equilibrium", "torque", "potential-energy", "orientation"], "payload": {"question_id": "cuet-phy-elec-dipole-29", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-3, D-4", "is_correct": true}, {"key": "C", "text": "A-3, B-1, C-2, D-4", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-4, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and D. At θ = 90°, the torque is maximum (pE), not (√3/2)pE. The factor √3/2 corresponds to sin60°, not sin90°.", "misconception": "Confusing the torque at 60° with that at 90°"}, {"option_key": "C", "hint": "This swaps A and C. At θ = 0° (parallel), U = −pE (stable), not +pE. At θ = 180° (antiparallel), U = +pE (unstable).", "misconception": "Reversing stable and unstable equilibrium positions"}, {"option_key": "D", "hint": "This assigns maximum torque to θ = 0°, but torque at θ = 0° is zero since sin0° = 0.", "misconception": "Thinking torque is maximum at aligned position"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the properties of electric field lines in Column I with the corresponding descriptions in Column II:\n\nColumn I:\nA. Density of field lines\nB. Tangent to a field line at a point\nC. Field lines in a uniform field\nD. Field lines near a positive point charge\n\nColumn II:\n1. Gives the direction of the electric field at that point\n2. Are parallel and equally spaced\n3. Radiate outward in all directions\n4. Represents the magnitude of the electric field", "explanation": "The density (closeness) of field lines represents the field magnitude → A-4. The tangent at any point on a field line gives the field direction at that point → B-1. In a uniform field, lines are parallel and equally spaced → C-2. Near a positive charge, lines radiate outward → D-3.", "correct_answer": "C", "concept_tags": ["field-line-properties", "field-magnitude", "field-direction", "uniform-field"], "payload": {"question_id": "cuet-phy-elec-dipole-30", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-4, C-2, D-3", "is_correct": false}, {"key": "B", "text": "A-4, B-1, C-3, D-2", "is_correct": false}, {"key": "C", "text": "A-4, B-1, C-2, D-3", "is_correct": true}, {"key": "D", "text": "A-3, B-2, C-1, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps A and B. Density of lines represents magnitude (not direction), and the tangent gives direction (not magnitude).", "misconception": "Confusing the role of field line density with tangent direction"}, {"option_key": "B", "hint": "This swaps C and D. A uniform field has parallel, equally spaced lines, while a point charge has radially diverging lines.", "misconception": "Confusing uniform field pattern with point charge pattern"}, {"option_key": "D", "hint": "This completely scrambles the matching. Density gives magnitude, tangent gives direction, uniform field lines are parallel, and positive charge lines radiate outward.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The net charge of an electric dipole is zero.", "explanation": "TRUE. An electric dipole consists of two equal and opposite charges: +q and −q. The net charge is +q + (−q) = 0. This is why the dipole field falls off as 1/r³ — the monopole (net charge) term is zero.", "correct_answer": "A", "concept_tags": ["dipole-net-charge", "zero-charge"], "payload": {"question_id": "cuet-phy-elec-dipole-31", "subtopic": "Dipole properties", "topic_name": "Electric Dipole", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "By definition, a dipole has +q and −q. Their algebraic sum is always zero.", "misconception": "Thinking a dipole has net charge because it has two charges"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The electric dipole moment is a vector quantity directed from the negative charge to the positive charge.", "explanation": "This statement is TRUE. The electric dipole moment p = qd is a vector quantity. By convention, its direction is defined from the negative charge (−q) to the positive charge (+q).", "correct_answer": "A", "concept_tags": ["dipole-moment", "vector-quantity", "direction-convention"], "payload": {"question_id": "cuet-phy-elec-dipole-32", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The dipole moment is indeed a vector, and its standard convention is from negative to positive charge. This is a well-established definition in physics.", "misconception": "Thinking the dipole moment is a scalar or directed from positive to negative"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The torque on an electric dipole aligned parallel to a uniform electric field is maximum.", "explanation": "FALSE. Torque τ = pE sinθ. When the dipole is parallel to the field (θ = 0°), sin0° = 0, so τ = 0 (minimum, stable equilibrium). Maximum torque occurs at θ = 90° (perpendicular to the field).", "correct_answer": "B", "concept_tags": ["torque", "parallel-alignment", "zero-torque"], "payload": {"question_id": "cuet-phy-elec-dipole-33", "subtopic": "Torque on dipole", "topic_name": "Electric Dipole", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "At θ = 0° (parallel), sinθ = 0, so torque is zero. The maximum torque occurs at θ = 90° (perpendicular), where sinθ = 1.", "misconception": "Confusing minimum torque (stable equilibrium) with maximum torque"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electric field lines can form closed loops in electrostatic conditions.", "explanation": "This statement is FALSE. Electrostatic field lines never form closed loops. They always begin at positive charges and end at negative charges. Closed loops of field lines are a characteristic of magnetic field lines or the electric field lines of time-varying magnetic fields, not electrostatic fields.", "correct_answer": "B", "concept_tags": ["field-lines-no-loops", "electrostatics", "conservative-field"], "payload": {"question_id": "cuet-phy-elec-dipole-34", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrostatic fields are conservative, meaning the work done around a closed loop is zero. This requires that field lines cannot form closed loops.", "misconception": "Confusing electrostatic field lines with magnetic field lines which do form closed loops"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The SI unit of electric dipole moment is ______.", "explanation": "Electric dipole moment p = q × d, where q is charge (coulomb) and d is distance (metre). Therefore, SI unit = C·m (coulomb-metre). It is a vector quantity directed from −q to +q.", "correct_answer": "B", "concept_tags": ["dipole-moment-unit", "SI-units", "definition"], "payload": {"question_id": "cuet-phy-elec-dipole-35", "subtopic": "Dipole moment basics", "topic_name": "Electric Dipole", "bloom_level": "remember", "options": [{"key": "A", "text": "C/m", "is_correct": false}, {"key": "B", "text": "C·m", "is_correct": true}, {"key": "C", "text": "N/C", "is_correct": false}, {"key": "D", "text": "V·m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "C/m (coulomb per metre) is related to linear charge density, not dipole moment. Dipole moment = charge × distance, not charge ÷ distance.", "misconception": "Dividing instead of multiplying charge by distance"}, {"option_key": "C", "hint": "N/C is the unit of electric field, not dipole moment.", "misconception": "Confusing dipole moment with electric field"}, {"option_key": "D", "hint": "V·m is equivalent to N·m²/C which relates to electric flux, not dipole moment.", "misconception": "Confusing dipole moment with flux"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The ratio of the electric field on the axial line to the equatorial line of a dipole at the same large distance r is _____.", "explanation": "E_axial = 2kp/r³, E_equatorial = kp/r³. Ratio = 2kp/r³ ÷ kp/r³ = 2. The axial field is always twice the equatorial field at the same distance from the dipole centre.", "correct_answer": "C", "concept_tags": ["axial-equatorial-ratio", "dipole-field"], "payload": {"question_id": "cuet-phy-elec-dipole-36", "subtopic": "Dipole field comparison", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "1/2", "is_correct": false}, {"key": "C", "text": "2", "is_correct": true}, {"key": "D", "text": "3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Ratio = 1 would mean both fields are equal, but E_axial has a factor of 2 that E_equatorial doesn''t.", "misconception": "Thinking the dipole field is the same in all directions"}, {"option_key": "B", "hint": "1/2 inverts the ratio — the axial field is stronger (×2), not weaker (÷2).", "misconception": "Inverting the axial/equatorial ratio"}, {"option_key": "D", "hint": "A ratio of 3 doesn''t arise from the dipole field formulas. The exact ratio is 2:1.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["NEET", "CUET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A water molecule has a permanent electric dipole moment of approximately 6.2 × 10⁻³⁰ C·m. It is placed in an external uniform electric field of 2 × 10⁶ N/C. Initially, the dipole moment makes an angle of 90° with the field direction.\n\nWhat is the work done by the external field in rotating the water molecule from 90° to the position of stable equilibrium (0°)?", "explanation": "Work done by the field = −ΔU = −[U_final − U_initial] = −[(−pE cos0°) − (−pE cos90°)] = −[−pE − 0] = pE. So W = pE = 6.2 × 10⁻³⁰ × 2 × 10⁶ = 12.4 × 10⁻²⁴ J = 1.24 × 10⁻²³ J. The field does positive work as the dipole moves toward stable equilibrium.", "correct_answer": "B", "concept_tags": ["dipole-in-field", "work-done", "water-molecule", "stable-equilibrium"], "payload": {"question_id": "cuet-phy-elec-dipole-37", "subtopic": "", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "6.2 × 10⁻²⁴ J", "is_correct": false}, {"key": "B", "text": "1.24 × 10⁻²³ J", "is_correct": true}, {"key": "C", "text": "2.48 × 10⁻²³ J", "is_correct": false}, {"key": "D", "text": "3.1 × 10⁻²⁴ J", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This result comes from multiplying only p × E with a computational error. The correct product is 6.2 × 10⁻³⁰ × 2 × 10⁶ = 12.4 × 10⁻²⁴ = 1.24 × 10⁻²³ J.", "misconception": "Arithmetic error in powers of ten"}, {"option_key": "C", "hint": "2.48 × 10⁻²³ J = 2pE, which would be the work done in rotating from 180° to 0°, not from 90° to 0°.", "misconception": "Using the formula for rotation from antiparallel to parallel position"}, {"option_key": "D", "hint": "3.1 × 10⁻²⁴ J = pE/4, which does not correspond to any standard dipole rotation. The work from 90° to 0° is simply pE.", "misconception": "Dividing by an incorrect factor"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A water molecule has an electric dipole moment of 6.1 × 10⁻³⁰ C·m. It is placed in a uniform electric field of 2 × 10⁵ N/C. Calculate the maximum torque and the work done in rotating it from the position of stable equilibrium to the position of unstable equilibrium.", "explanation": "Maximum torque: τ_max = pE = 6.1 × 10⁻³⁰ × 2 × 10⁵ = 1.22 × 10⁻²⁴ N·m (occurs at θ = 90°). Work done from 0° to 180°: W = pE(cos0° − cos180°) = pE(1−(−1)) = 2pE = 2 × 6.1 × 10⁻³⁰ × 2 × 10⁵ = 2.44 × 10⁻²⁴ J.", "correct_answer": "D", "concept_tags": ["water-molecule", "dipole-torque", "work-done"], "payload": {"question_id": "cuet-phy-elec-dipole-38", "subtopic": "Real-world dipole applications", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "τ_max = 1.22 × 10⁻²⁴ N·m; W = 1.22 × 10⁻²⁴ J", "is_correct": false}, {"key": "B", "text": "τ_max = 2.44 × 10⁻²⁴ N·m; W = 2.44 × 10⁻²⁴ J", "is_correct": false}, {"key": "C", "text": "τ_max = 6.1 × 10⁻²⁵ N·m; W = 1.22 × 10⁻²⁴ J", "is_correct": false}, {"key": "D", "text": "τ_max = 1.22 × 10⁻²⁴ N·m; W = 2.44 × 10⁻²⁴ J", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The torque is correct but the work should be 2pE (not pE). Work for 0° → 180° involves a factor of 2.", "misconception": "Using W = pE instead of W = 2pE for full 180° rotation"}, {"option_key": "B", "hint": "The maximum torque is pE, not 2pE. The factor 2 applies to work, not torque.", "misconception": "Confusing the formula for torque with the formula for work"}, {"option_key": "C", "hint": "6.1 × 10⁻²⁵ comes from dividing pE by 2, but maximum torque is simply pE (sinθ_max = 1, not 1/2).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following positions of an electric dipole in a uniform electric field in order of increasing potential energy:\n\n1. θ = 180° (antiparallel to field)\n2. θ = 0° (parallel to field)\n3. θ = 90° (perpendicular to field)\n4. θ = 60° (at 60° to field)", "explanation": "U = −pE cosθ. Calculate: U(0°) = −pE, U(60°) = −pE/2, U(90°) = 0, U(180°) = +pE. Increasing order: −pE < −pE/2 < 0 < +pE. So: θ = 0° < θ = 60° < θ = 90° < θ = 180°, i.e., 2 → 4 → 3 → 1.", "correct_answer": "B", "concept_tags": ["potential-energy", "dipole-orientation", "ordering"], "payload": {"question_id": "cuet-phy-elec-dipole-39", "subtopic": "Energy of dipole in field", "topic_name": "Electric Dipole", "bloom_level": "apply", "options": [{"key": "A", "text": "1 → 3 → 4 → 2", "is_correct": false}, {"key": "B", "text": "2 → 4 → 3 → 1", "is_correct": true}, {"key": "C", "text": "2 → 3 → 4 → 1", "is_correct": false}, {"key": "D", "text": "3 → 2 → 4 → 1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This starts with θ = 180° (highest energy) and ends with θ = 0° (lowest). That''s decreasing order, not increasing.", "misconception": "Reversing the order"}, {"option_key": "C", "hint": "This places θ = 90° (U = 0) before θ = 60° (U = −pE/2). But −pE/2 < 0, so 60° has lower energy than 90°.", "misconception": "Not computing U(60°) correctly"}, {"option_key": "D", "hint": "This starts with θ = 90° (U = 0) but θ = 0° (U = −pE) has the lowest energy and should come first.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following orientations of an electric dipole in a uniform electric field in order of increasing potential energy (from most negative to most positive):", "explanation": "Potential energy U = −pE cosθ. At θ = 0°: U = −pE (minimum, most stable). At θ = 60°: U = −pE cos60° = −pE/2. At θ = 90°: U = −pE cos90° = 0. At θ = 180°: U = −pE cos180° = +pE (maximum, most unstable). The order from most negative to most positive is: −pE < −pE/2 < 0 < +pE.", "correct_answer": "C", "concept_tags": ["dipole-potential-energy", "orientation-dependence", "stability"], "payload": {"question_id": "cuet-phy-elec-dipole-40", "subtopic": "Potential energy of dipole in field", "topic_name": "Electric Dipole", "bloom_level": "analyze", "options": [{"key": "A", "text": "θ = 0° → θ = 60° → θ = 180° → θ = 90°", "is_correct": false}, {"key": "B", "text": "θ = 180° → θ = 90° → θ = 60° → θ = 0°", "is_correct": false}, {"key": "C", "text": "θ = 0° → θ = 60° → θ = 90° → θ = 180°", "is_correct": true}, {"key": "D", "text": "θ = 90° → θ = 0° → θ = 60° → θ = 180°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This places θ = 180° before θ = 90°. Since U(180°) = +pE > U(90°) = 0, this order is wrong.", "misconception": "Incorrect ordering of potential energy values"}, {"option_key": "B", "hint": "This is the DECREASING order (most positive first). The question asks for INCREASING order (most negative first).", "misconception": "Reversing the requested order"}, {"option_key": "D", "hint": "This places θ = 90° (U = 0) as the lowest energy, but θ = 0° (U = −pE) has the lowest (most negative) energy.", "misconception": "Assuming perpendicular orientation has minimum energy"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Gauss''s law relates the electric flux through a closed surface to the:", "explanation": "Gauss''s law states Φ = q_enclosed/ε₀. It relates the total electric flux through any closed (Gaussian) surface to the net charge enclosed within that surface divided by ε₀. It does not depend on charges outside the surface.", "correct_answer": "C", "concept_tags": ["gauss-law", "enclosed-charge", "flux"], "payload": {"question_id": "cuet-phy-elec-gauss-01", "subtopic": "Statement of Gauss''s law", "topic_name": "Gauss''s Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "Total charge in the universe", "is_correct": false}, {"key": "B", "text": "Charge on the surface itself", "is_correct": false}, {"key": "C", "text": "Net charge enclosed within the surface", "is_correct": true}, {"key": "D", "text": "Charge outside the closed surface", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Gauss''s law is local — it only cares about charge inside the Gaussian surface, not all charge in the universe.", "misconception": "Thinking flux depends on all charges everywhere"}, {"option_key": "B", "hint": "The charge must be enclosed (inside) the surface, not on the surface. A charge on the surface itself creates a mathematical ambiguity.", "misconception": "Confusing surface charge with enclosed charge"}, {"option_key": "D", "hint": "Charges outside contribute zero net flux through the closed surface — their field lines enter and exit, cancelling.", "misconception": "Thinking external charges contribute to net flux"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The Gaussian surface used to find the electric field of an infinitely long uniformly charged wire is:", "explanation": "For a line charge, we exploit the cylindrical symmetry. A coaxial cylinder (with its axis along the wire) makes E constant on the curved surface and perpendicular to the flat ends. This simplifies ∮E·dA to E × 2πrL, allowing easy calculation.", "correct_answer": "B", "concept_tags": ["gaussian-surface", "cylindrical-symmetry", "line-charge"], "payload": {"question_id": "cuet-phy-elec-gauss-02", "subtopic": "Choice of Gaussian surface", "topic_name": "Gauss''s Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "A sphere centred on the wire", "is_correct": false}, {"key": "B", "text": "A coaxial cylinder with the wire as axis", "is_correct": true}, {"key": "C", "text": "A cube enclosing the wire", "is_correct": false}, {"key": "D", "text": "A flat rectangular surface", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A sphere doesn''t match the cylindrical symmetry of the wire. E would vary over the sphere''s surface, making the integral unsolvable simply.", "misconception": "Using wrong symmetry surface"}, {"option_key": "C", "hint": "While Gauss''s law is valid for any surface, a cube doesn''t exploit the symmetry. E would not be constant on any face.", "misconception": "Ignoring the importance of symmetry for practical calculation"}, {"option_key": "D", "hint": "Gauss''s law requires a closed surface. A flat rectangle is an open surface — flux through it doesn''t equal q/ε₀.", "misconception": "Forgetting Gauss''s law needs a closed surface"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "If a positive charge q is placed at the centre of a cube, the electric flux through each face is:", "explanation": "By Gauss''s law, total flux = q/ε₀. By symmetry of the cube, all six faces receive equal flux. So flux through each face = q/(6ε₀). This is a classic application of symmetry arguments with Gauss''s law.", "correct_answer": "A", "concept_tags": ["cube-flux", "symmetry", "gauss-law"], "payload": {"question_id": "cuet-phy-elec-gauss-03", "subtopic": "Flux through symmetric surfaces", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "q/(6ε₀)", "is_correct": true}, {"key": "B", "text": "q/ε₀", "is_correct": false}, {"key": "C", "text": "q/(4ε₀)", "is_correct": false}, {"key": "D", "text": "6q/ε₀", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "q/ε₀ is the total flux through the entire cube (all 6 faces), not through one face.", "misconception": "Using total flux instead of dividing by number of faces"}, {"option_key": "C", "hint": "Dividing by 4 suggests confusing with a tetrahedron (4 faces) or a sphere formula. A cube has 6 faces.", "misconception": "Wrong number of faces for a cube"}, {"option_key": "D", "hint": "6q/ε₀ multiplies by 6 instead of dividing. Each face gets 1/6 of the total flux, not 6 times.", "misconception": "Multiplying instead of dividing by number of faces"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric field inside a uniformly charged spherical shell (hollow sphere) is:", "explanation": "By Gauss''s law, for any Gaussian sphere of radius r < R (inside the shell), the enclosed charge is zero (all charge is on the shell surface). Therefore E × 4πr² = 0/ε₀, giving E = 0 inside. This result holds everywhere inside, not just at the centre.", "correct_answer": "D", "concept_tags": ["shell-theorem", "zero-field-inside", "gauss-law"], "payload": {"question_id": "cuet-phy-elec-gauss-04", "subtopic": "Field inside a shell", "topic_name": "Gauss''s Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "kQ/r² directed radially outward", "is_correct": false}, {"key": "B", "text": "kQ/R² directed radially inward", "is_correct": false}, {"key": "C", "text": "Uniform and non-zero", "is_correct": false}, {"key": "D", "text": "Zero everywhere inside", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "kQ/r² applies outside the shell (r > R). Inside (r < R), the enclosed charge is zero.", "misconception": "Applying the external field formula inside the shell"}, {"option_key": "B", "hint": "There is no inward field. The enclosed charge is zero, so the field is zero, not inward.", "misconception": "Thinking the shell attracts test charges inside"}, {"option_key": "C", "hint": "A uniform non-zero field would violate Gauss''s law since there is no enclosed charge to produce such a field.", "misconception": "Confusing conductor with charged region"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Electric flux through a surface is defined as:", "explanation": "Electric flux (φ) through a surface is defined as the surface integral of the electric field over that surface, i.e., φ = ∫E·dA. For a uniform field and a flat surface, it simplifies to φ = E·A = EA cosθ, where θ is the angle between the field and the area vector.", "correct_answer": "B", "concept_tags": ["electric-flux", "surface-integral", "dot-product"], "payload": {"question_id": "cuet-phy-elec-gauss-05", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "E × A (cross product of field and area)", "is_correct": false}, {"key": "B", "text": "E · A (dot product of field and area vector)", "is_correct": true}, {"key": "C", "text": "E / A (field divided by area)", "is_correct": false}, {"key": "D", "text": "E + A (sum of field and area)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The cross product gives a vector, but electric flux is a scalar quantity. The correct operation is the dot product E·A.", "misconception": "Confusing dot product with cross product"}, {"option_key": "C", "hint": "E/A does not define flux; dividing field by area has no standard physical meaning in this context.", "misconception": null}, {"option_key": "D", "hint": "Adding a field vector and an area vector is not a physically meaningful operation; flux involves multiplication, not addition.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of electric flux is:", "explanation": "Electric flux φ = E·A has dimensions of electric field (N/C) times area (m²). Therefore, its SI unit is N·m²/C, which is also equivalent to V·m (volt-metre).", "correct_answer": "A", "concept_tags": ["electric-flux", "SI-units", "dimensional-analysis"], "payload": {"question_id": "cuet-phy-elec-gauss-06", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "N·m²/C", "is_correct": true}, {"key": "B", "text": "N/C", "is_correct": false}, {"key": "C", "text": "N·m/C²", "is_correct": false}, {"key": "D", "text": "C/m²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "N/C is the unit of electric field intensity, not flux. Flux includes multiplication by area (m²).", "misconception": "Confusing electric field units with flux units"}, {"option_key": "C", "hint": "N·m/C² does not correspond to any standard electromagnetic quantity.", "misconception": null}, {"option_key": "D", "hint": "C/m² is the unit of surface charge density, not electric flux.", "misconception": "Confusing flux with surface charge density"}]}}]'::jsonb, 'deploy-2026-03-05-b04');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A Gaussian sphere of radius r encloses a non-conducting solid sphere of radius R (r < R) carrying a uniform volume charge density ρ. The electric field at distance r from the centre is:", "explanation": "For r < R, the enclosed charge q_enc = ρ × (4/3)πr³. By Gauss''s law: E × 4πr² = ρ(4/3)πr³/ε₀. Solving: E = ρr/(3ε₀). The field increases linearly with r inside a uniformly charged sphere.", "correct_answer": "B", "concept_tags": ["solid-sphere", "linear-field", "volume-charge"], "payload": {"question_id": "cuet-phy-elec-gauss-07", "subtopic": "Field inside a solid sphere", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "ρR/(3ε₀)", "is_correct": false}, {"key": "B", "text": "ρr/(3ε₀)", "is_correct": true}, {"key": "C", "text": "ρr²/(3ε₀)", "is_correct": false}, {"key": "D", "text": "ρR³/(3ε₀r²)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This uses R instead of r. Inside the sphere, the field depends on the distance r from the centre, not the sphere radius R.", "misconception": "Using the total radius instead of the Gaussian radius"}, {"option_key": "C", "hint": "ρr²/(3ε₀) has the wrong power of r. The charge scales as r³ and the area as r², giving E ∝ r¹, not r².", "misconception": "Not correctly dividing the r³ charge by the r² area"}, {"option_key": "D", "hint": "ρR³/(3ε₀r²) is the field outside the sphere (r > R). Inside, only the charge within radius r counts.", "misconception": "Using the external field formula inside the sphere"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field due to an infinite plane sheet of surface charge density σ is:", "explanation": "Using a Gaussian pillbox straddling the sheet: flux through two flat faces = 2EA. Enclosed charge = σA. By Gauss''s law: 2EA = σA/ε₀, so E = σ/(2ε₀). The field is uniform (independent of distance), directed away from the sheet for positive σ.", "correct_answer": "C", "concept_tags": ["infinite-sheet", "uniform-field", "pillbox"], "payload": {"question_id": "cuet-phy-elec-gauss-08", "subtopic": "Field due to infinite sheet", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "σ/ε₀, perpendicular to the sheet", "is_correct": false}, {"key": "B", "text": "σ/(4πε₀r²), decreasing with distance", "is_correct": false}, {"key": "C", "text": "σ/(2ε₀), perpendicular to the sheet", "is_correct": true}, {"key": "D", "text": "2σ/ε₀, parallel to the sheet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "σ/ε₀ is the field between two parallel plates (with charges +σ and −σ). For a single sheet, the factor 2 in the denominator is essential.", "misconception": "Confusing single sheet with parallel plate capacitor"}, {"option_key": "B", "hint": "The field of an infinite sheet is independent of distance — it doesn''t follow an inverse-square law.", "misconception": "Applying point charge formula to an infinite sheet"}, {"option_key": "D", "hint": "The field is perpendicular (normal) to the sheet, not parallel. Also, 2σ/ε₀ has the wrong magnitude.", "misconception": "Wrong direction and magnitude"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charge of 8.85 μC is placed at the centre of a hollow sphere of radius 10 cm. The electric flux through the sphere (ε₀ = 8.85 × 10⁻¹² C²/N·m²) is:", "explanation": "Φ = q/ε₀ = 8.85 × 10⁻⁶ / 8.85 × 10⁻¹² = 10⁶ N·m²/C = 10⁶ V·m. Note that the flux depends only on the enclosed charge, not on the radius of the sphere.", "correct_answer": "B", "concept_tags": ["numerical-flux", "gauss-law"], "payload": {"question_id": "cuet-phy-elec-gauss-09", "subtopic": "Flux calculation", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "10⁵ N·m²/C", "is_correct": false}, {"key": "B", "text": "10⁶ N·m²/C", "is_correct": true}, {"key": "C", "text": "10⁷ N·m²/C", "is_correct": false}, {"key": "D", "text": "8.85 × 10⁶ N·m²/C", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10⁵ is off by a factor of 10. Check: 10⁻⁶/10⁻¹² = 10⁶, not 10⁵.", "misconception": "Arithmetic error in exponent subtraction"}, {"option_key": "C", "hint": "10⁷ overshoots by a factor of 10. The ratio 8.85/8.85 = 1, so Φ = 1 × 10⁶.", "misconception": null}, {"option_key": "D", "hint": "The 8.85 in the numerator and denominator cancel exactly, giving 10⁶, not 8.85 × 10⁶.", "misconception": "Not cancelling the 8.85 factor"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field between two large parallel plates carrying surface charge densities +σ and −σ is:", "explanation": "Each plate produces a field σ/(2ε₀). Between the plates, both fields point in the same direction (from +σ to −σ), so they add: E = σ/(2ε₀) + σ/(2ε₀) = σ/ε₀. Outside both plates, the fields cancel to zero.", "correct_answer": "A", "concept_tags": ["parallel-plates", "superposition", "uniform-field"], "payload": {"question_id": "cuet-phy-elec-gauss-10", "subtopic": "Parallel plate field", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "σ/ε₀", "is_correct": true}, {"key": "B", "text": "σ/(2ε₀)", "is_correct": false}, {"key": "C", "text": "2σ/ε₀", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "σ/(2ε₀) is the field due to one plate alone. Between the plates, both plates contribute, doubling the field to σ/ε₀.", "misconception": "Forgetting the contribution of the second plate"}, {"option_key": "C", "hint": "2σ/ε₀ doubles the correct answer. Each plate gives σ/(2ε₀), and they add to σ/ε₀, not 2σ/ε₀.", "misconception": "Doubling the already-added field"}, {"option_key": "D", "hint": "Zero is the field outside the plates (where fields cancel). Between the plates, the fields reinforce.", "misconception": "Confusing the region between plates with region outside"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field just outside the surface of a charged conductor with local surface charge density σ is:", "explanation": "For a conductor, all charge resides on the surface. Using a small Gaussian pillbox at the surface: one face inside (E = 0), one face outside (E outward). Flux = EA = σA/ε₀, giving E = σ/ε₀. Note: no factor of 2 because the internal field is zero.", "correct_answer": "D", "concept_tags": ["conductor-surface-field", "pillbox", "boundary-condition"], "payload": {"question_id": "cuet-phy-elec-gauss-11", "subtopic": "Field at conductor surface", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "σ/(2ε₀)", "is_correct": false}, {"key": "B", "text": "2σ/ε₀", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "σ/ε₀", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "σ/(2ε₀) applies to an infinite non-conducting sheet (both sides contribute). For a conductor, E = 0 inside, so the full field σ/ε₀ appears outside.", "misconception": "Confusing conductor with non-conducting sheet"}, {"option_key": "B", "hint": "2σ/ε₀ overestimates the field by a factor of 2. The Gauss''s law pillbox gives E = σ/ε₀ directly.", "misconception": null}, {"option_key": "C", "hint": "E = 0 inside the conductor, but just outside the surface the field is σ/ε₀, not zero.", "misconception": "Confusing ''inside'' the conductor with ''just outside'' the surface"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charge of 5 μC is placed at the centre of a cube. The electric flux through one face of the cube is:", "explanation": "By Gauss''s law, total flux through the cube = q/ε₀ = 5 × 10⁻⁶ / (8.85 × 10⁻¹²) ≈ 5.65 × 10⁵ N·m²/C. By symmetry, the flux is equally distributed among all 6 faces. Flux through one face = q/(6ε₀) ≈ 9.41 × 10⁴ N·m²/C.", "correct_answer": "B", "concept_tags": ["gauss-law", "cube-symmetry", "flux-distribution"], "payload": {"question_id": "cuet-phy-elec-gauss-12", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "5.65 × 10⁵ N·m²/C", "is_correct": false}, {"key": "B", "text": "9.41 × 10⁴ N·m²/C", "is_correct": true}, {"key": "C", "text": "2.83 × 10⁵ N·m²/C", "is_correct": false}, {"key": "D", "text": "1.13 × 10⁵ N·m²/C", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "5.65 × 10⁵ is the total flux through the entire closed cube (q/ε₀). You need to divide by 6 for one face.", "misconception": "Using total flux instead of flux through one face"}, {"option_key": "C", "hint": "2.83 × 10⁵ would be q/(2ε₀), as if dividing by 2 instead of 6. A cube has 6 faces, not 2.", "misconception": "Dividing by 2 instead of 6"}, {"option_key": "D", "hint": "This value does not correspond to q/(6ε₀). The correct calculation is (5 × 10⁻⁶)/(6 × 8.85 × 10⁻¹²) ≈ 9.41 × 10⁴.", "misconception": "Arithmetic error in division"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field due to an infinitely long straight uniformly charged wire with linear charge density λ at a perpendicular distance r from the wire is:", "explanation": "Using Gauss''s law with a cylindrical Gaussian surface of radius r and length L coaxial with the wire: φ = E(2πrL) = λL/ε₀. Solving, E = λ/(2πε₀r). The field is directed radially outward for positive λ and decreases as 1/r.", "correct_answer": "C", "concept_tags": ["infinite-line-charge", "gauss-law-application", "cylindrical-symmetry"], "payload": {"question_id": "cuet-phy-elec-gauss-13", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "λ/(4πε₀r)", "is_correct": false}, {"key": "B", "text": "λ/(4πε₀r²)", "is_correct": false}, {"key": "C", "text": "λ/(2πε₀r)", "is_correct": true}, {"key": "D", "text": "λ/(2πε₀r²)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The factor 4π appears in the point charge field formula (Coulomb''s law). For a line charge with cylindrical symmetry, the correct factor is 2π.", "misconception": "Using 4π (spherical) instead of 2π (cylindrical) geometry"}, {"option_key": "B", "hint": "This has both an incorrect 4π factor and an incorrect 1/r² dependence. The line charge field varies as 1/r, not 1/r².", "misconception": "Combining errors from spherical geometry and inverse square law"}, {"option_key": "D", "hint": "The field from an infinite line charge varies as 1/r, not 1/r². The 1/r² dependence applies to point charges.", "misconception": "Applying inverse square law to a line charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field due to an infinite plane sheet of uniform surface charge density σ is:", "explanation": "Using Gauss''s law with a Gaussian pillbox (cylinder) straddling the sheet: 2EA = σA/ε₀, giving E = σ/(2ε₀). This field is uniform (independent of distance from the sheet) and directed perpendicular to the sheet, away from it for positive σ.", "correct_answer": "A", "concept_tags": ["infinite-plane-sheet", "gauss-law-application", "uniform-field"], "payload": {"question_id": "cuet-phy-elec-gauss-14", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "σ/(2ε₀), independent of distance", "is_correct": true}, {"key": "B", "text": "σ/ε₀, independent of distance", "is_correct": false}, {"key": "C", "text": "σ/(2ε₀r), varying with distance r", "is_correct": false}, {"key": "D", "text": "σ/(2ε₀r²), varying with distance r", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "σ/ε₀ is the field between two parallel infinite sheets of opposite charge (or near a conductor surface), not for a single sheet.", "misconception": "Confusing single sheet field with parallel plate or conductor surface field"}, {"option_key": "C", "hint": "The electric field due to an infinite plane sheet does not depend on the distance from the sheet; the Gaussian pillbox analysis shows E is constant.", "misconception": "Incorrectly assuming distance dependence for an infinite sheet"}, {"option_key": "D", "hint": "An inverse square dependence on distance applies to point charges, not to an infinite plane sheet.", "misconception": "Applying point charge formula to a plane sheet"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A uniformly charged hollow spherical shell of total charge Q and radius R. The electric field at a point inside the shell (r < R) is:", "explanation": "By Gauss''s law, using a spherical Gaussian surface of radius r < R inside the shell, the enclosed charge is zero (all charge is on the shell surface). Therefore, E = 0 inside a uniformly charged hollow sphere. This result is independent of the position inside the shell.", "correct_answer": "D", "concept_tags": ["hollow-sphere", "gauss-law", "shell-theorem"], "payload": {"question_id": "cuet-phy-elec-gauss-15", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "kQ/r²", "is_correct": false}, {"key": "B", "text": "kQ/R²", "is_correct": false}, {"key": "C", "text": "kQr/R³", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "kQ/r² would apply if all the charge Q were at the centre. Inside a shell, the enclosed charge is zero, so the field is zero.", "misconception": "Treating the shell as a point charge at the centre"}, {"option_key": "B", "hint": "kQ/R² is the field at the surface of the shell, not inside it.", "misconception": "Confusing field at the surface with field inside"}, {"option_key": "C", "hint": "kQr/R³ describes the field inside a uniformly charged solid non-conducting sphere, not a hollow shell.", "misconception": "Confusing hollow shell with solid sphere"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "medium", "question_text": "For a uniformly charged solid non-conducting sphere of total charge Q and radius R, the electric field at an internal point at distance r from the centre (r < R) is:", "explanation": "Using Gauss''s law, the charge enclosed by a Gaussian sphere of radius r is q_enc = Q(r³/R³) (since charge is proportional to volume). Then E(4πr²) = Q(r³/R³)/ε₀, giving E = Qr/(4πε₀R³) = kQr/R³. The field increases linearly from the centre.", "correct_answer": "B", "concept_tags": ["solid-sphere", "gauss-law", "linear-field"], "payload": {"question_id": "cuet-phy-elec-gauss-16", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "kQ/r²", "is_correct": false}, {"key": "B", "text": "kQr/R³", "is_correct": true}, {"key": "C", "text": "kQ/R²", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "kQ/r² gives the field outside the sphere (r > R), not inside. Inside, only the charge enclosed within radius r contributes.", "misconception": "Using total charge instead of enclosed charge for r < R"}, {"option_key": "C", "hint": "kQ/R² is the field at the surface (r = R). Inside, the enclosed charge is less than Q, giving a smaller field.", "misconception": "Using the surface field value everywhere inside"}, {"option_key": "D", "hint": "Zero field inside applies to a hollow conducting shell, not to a uniformly charged solid non-conducting sphere.", "misconception": "Confusing solid non-conducting sphere with hollow conducting shell"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A uniformly charged non-conducting sphere of radius R and total charge Q has a spherical cavity of radius R/2 centred at distance R/2 from the centre. The electric field at the centre of the cavity is:", "explanation": "Using the superposition principle: E = E_full − E_removed. For the full sphere at R/2 from centre: E_full = ρ(R/2)/(3ε₀) directed outward. The removed sphere (radius R/2, centred at R/2 from main centre) contributes E_removed = 0 at its own centre. So E at cavity centre = ρR/(6ε₀) = Q/(4πε₀) × 1/(2R²) directed away from the main centre. Using ρ = Q/(4πR³/3) = 3Q/(4πR³): E = 3Q/(4πR³) × R/(6ε₀) = Q/(8πε₀R²).", "correct_answer": "C", "concept_tags": ["cavity-field", "superposition", "non-uniform-sphere"], "payload": {"question_id": "cuet-phy-elec-gauss-17", "subtopic": "Cavity problems", "topic_name": "Gauss''s Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "Q/(4πε₀R²)", "is_correct": false}, {"key": "C", "text": "Q/(8πε₀R²)", "is_correct": true}, {"key": "D", "text": "Q/(16πε₀R²)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Zero field would occur inside a complete spherical shell, not inside a cavity in a solid sphere with an off-centre hole.", "misconception": "Applying shell theorem to a non-symmetric cavity"}, {"option_key": "B", "hint": "Q/(4πε₀R²) is the surface field of the full sphere. The field at the cavity centre is weaker due to the offset and missing charge.", "misconception": "Using the full-sphere surface field formula"}, {"option_key": "D", "hint": "Q/(16πε₀R²) underestimates by a factor of 2. Check: ρR/(6ε₀) with ρ = 3Q/(4πR³) gives Q/(8πε₀R²).", "misconception": "Arithmetic error in density substitution"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A uniformly charged solid sphere has charge density ρ. The ratio of the electric field at distance R/2 from the centre to that at distance 2R from the centre (R is the radius) is:", "explanation": "At r = R/2 (inside): E_in = ρr/(3ε₀) = ρR/(6ε₀). At r = 2R (outside): E_out = ρR³/(3ε₀r²) = ρR³/(3ε₀ × 4R²) = ρR/(12ε₀). Ratio = [ρR/(6ε₀)] / [ρR/(12ε₀)] = 12/6 = 2.", "correct_answer": "D", "concept_tags": ["solid-sphere", "field-ratio", "inside-outside"], "payload": {"question_id": "cuet-phy-elec-gauss-18", "subtopic": "Solid sphere field", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "1/4", "is_correct": false}, {"key": "B", "text": "1/2", "is_correct": false}, {"key": "C", "text": "4", "is_correct": false}, {"key": "D", "text": "2", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1/4 would apply if both points were outside and the ratio were (R₁/R₂)² = (1/2)² = 1/4. But the inner point follows a different (linear) law.", "misconception": "Applying inverse square law at both points"}, {"option_key": "B", "hint": "1/2 would be the ratio of distances (R/2)/(R) but the fields follow different laws inside and outside.", "misconception": "Using simple distance ratio"}, {"option_key": "C", "hint": "4 is the inverse of 1/4. The correct ratio requires using ρr/(3ε₀) inside and ρR³/(3ε₀r²) outside.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two large parallel conducting plates carry surface charge densities +σ and −σ respectively. The electric field in the region between the plates is:", "explanation": "Each infinite conducting plate produces a field of σ/(2ε₀) on each side. Between the plates, the fields from both plates add up (both point from + to − plate): E = σ/(2ε₀) + σ/(2ε₀) = σ/ε₀. Outside the plates, the fields cancel, giving zero.", "correct_answer": "D", "concept_tags": ["parallel-plates", "superposition", "conductor-surface-field"], "payload": {"question_id": "cuet-phy-elec-gauss-19", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "σ/(2ε₀)", "is_correct": false}, {"key": "B", "text": "2σ/ε₀", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "σ/ε₀", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "σ/(2ε₀) is the field due to a single infinite sheet. Between two oppositely charged plates, both fields add, giving σ/ε₀.", "misconception": "Using single sheet formula without superposition"}, {"option_key": "B", "hint": "2σ/ε₀ would imply four times the single-sheet field. The correct superposition gives σ/(2ε₀) + σ/(2ε₀) = σ/ε₀.", "misconception": "Doubling the already-combined field"}, {"option_key": "C", "hint": "Zero is the field outside the plates where the fields cancel. Between the plates, the fields reinforce each other.", "misconception": "Confusing the field between plates with the field outside"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A solid conducting sphere of radius R carries a total charge Q. The surface charge density at the surface of the sphere and the electric field just outside the surface are, respectively:", "explanation": "For a conducting sphere, all charge resides on the surface. Surface charge density σ = Q/(4πR²). The electric field just outside a conductor surface is E = σ/ε₀ (by Gauss''s law using a small pillbox at the surface). Substituting σ: E = Q/(4πε₀R²) = kQ/R². This is consistent with treating the sphere as a point charge at large distances.", "correct_answer": "B", "concept_tags": ["conducting-sphere", "surface-charge-density", "field-at-surface"], "payload": {"question_id": "cuet-phy-elec-gauss-20", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "σ = Q/(4πR²), E = σ/(2ε₀)", "is_correct": false}, {"key": "B", "text": "σ = Q/(4πR²), E = σ/ε₀", "is_correct": true}, {"key": "C", "text": "σ = Q/(2πR²), E = σ/ε₀", "is_correct": false}, {"key": "D", "text": "σ = Q/(4πR²), E = 2σ/ε₀", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "σ/(2ε₀) is the field due to an infinite sheet. Near a conductor surface, the field is σ/ε₀ because there is field on only one side.", "misconception": "Using the infinite sheet formula σ/(2ε₀) instead of the conductor surface formula σ/ε₀"}, {"option_key": "C", "hint": "The surface area of a sphere is 4πR², not 2πR². Therefore σ = Q/(4πR²).", "misconception": "Using incorrect formula for sphere surface area"}, {"option_key": "D", "hint": "The field just outside a conductor is σ/ε₀, not 2σ/ε₀. The factor of 2 does not appear because the field exists only on the outer side.", "misconception": "Incorrectly doubling the conductor surface field"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Gauss''s law is valid for any closed surface, regardless of its shape.\nReason (R): The electric flux through any closed surface depends only on the net charge enclosed, not on the shape or size of the surface.", "explanation": "Both A and R are true, and R is the correct explanation of A. Gauss''s law ∮E·dA = q_enc/ε₀ holds for any arbitrary closed surface. Since the right-hand side depends only on enclosed charge (not surface geometry), the law''s validity is independent of surface shape. This generality is what makes Gauss''s law powerful.", "correct_answer": "A", "concept_tags": ["gauss-law-generality", "surface-independence"], "payload": {"question_id": "cuet-phy-elec-gauss-25", "subtopic": "Properties of Gauss''s law", "topic_name": "Gauss''s Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains why A is true — the shape-independence of Gauss''s law follows precisely because flux depends only on enclosed charge.", "misconception": "Not recognising the direct causal connection"}, {"option_key": "C", "hint": "R is correct. This is a fundamental property of Gauss''s law — flux through a closed surface depends on q_enclosed, not surface geometry.", "misconception": null}, {"option_key": "D", "hint": "A is correct. Gauss''s law applies to any closed surface — spheres, cubes, irregular shapes, etc.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The electric flux through a closed surface does not change when the shape of the surface is changed, keeping the enclosed charge the same.\nReason (R): According to Gauss''s law, electric flux through a closed surface depends only on the net charge enclosed, not on the shape or size of the surface.", "explanation": "The assertion is correct: Gauss''s law states φ = q_enclosed/ε₀, which depends only on the enclosed charge. The reason is also correct and directly explains the assertion. Since flux equals q/ε₀ regardless of surface geometry, changing the shape while keeping the same enclosed charge leaves the flux unchanged.", "correct_answer": "A", "concept_tags": ["gauss-law", "surface-independence", "electric-flux"], "payload": {"question_id": "cuet-phy-elec-gauss-26", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason is the direct mathematical statement (Gauss''s law) that explains why the flux is shape-independent. It is the correct explanation.", "misconception": "Not recognizing that Gauss''s law directly explains the shape independence of flux"}, {"option_key": "C", "hint": "The reason is a correct statement of Gauss''s law, which is a fundamental theorem in electrostatics.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct; this is a direct consequence of Gauss''s law, which can be verified experimentally.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The electric field due to a uniformly charged infinite plane sheet is independent of distance from the sheet.\nReason (R): The infinite sheet has planar symmetry, and the Gaussian pillbox analysis yields a field that does not contain the distance variable.", "explanation": "Both A and R are true, and R correctly explains A. Using a Gaussian pillbox of arbitrary height h: flux = 2EA, enclosed charge = σA. This gives E = σ/(2ε₀), with no dependence on h (distance from the sheet). The reason is the planar symmetry — translating the pillbox up or down changes nothing.", "correct_answer": "A", "concept_tags": ["infinite-sheet", "distance-independence", "planar-symmetry"], "payload": {"question_id": "cuet-phy-elec-gauss-27", "subtopic": "Field of infinite sheet", "topic_name": "Gauss''s Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R explains precisely why A is true — the pillbox derivation produces E = σ/(2ε₀) with no distance term, which is the mathematical proof of the distance independence.", "misconception": "Not connecting the derivation with the result"}, {"option_key": "C", "hint": "R is correct — the pillbox analysis of an infinite sheet does yield σ/(2ε₀) with no distance variable. This is a standard derivation.", "misconception": null}, {"option_key": "D", "hint": "A is correct. E = σ/(2ε₀) is constant everywhere for an infinite sheet, confirmed experimentally and theoretically.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The electric field inside a hollow conducting sphere is zero even if there is an external electric field.\nReason (R): A conductor has free electrons that rearrange themselves on the surface to cancel the external field inside.", "explanation": "The assertion is correct: the field inside a hollow conductor is zero in electrostatic equilibrium, even in the presence of an external field (electrostatic shielding). The reason is also correct and explains the assertion: free electrons on the conductor surface redistribute to create an induced surface charge that exactly cancels the external field within the cavity.", "correct_answer": "A", "concept_tags": ["electrostatic-shielding", "faraday-cage", "conductor-properties"], "payload": {"question_id": "cuet-phy-elec-gauss-28", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The redistribution of surface charges (reason) is exactly the mechanism that cancels the field inside (assertion), making R the correct explanation of A.", "misconception": "Not connecting charge redistribution with field cancellation inside"}, {"option_key": "C", "hint": "The reason is scientifically correct; conductors do have free electrons that redistribute to achieve electrostatic equilibrium.", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct; electrostatic shielding is a well-established phenomenon (Faraday cage principle).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the charge distributions in Column I with the distance dependence of the electric field in Column II:\n\nColumn I:\nA. Point charge\nB. Infinite line charge\nC. Infinite plane sheet\nD. Inside a uniformly charged solid sphere\n\nColumn II:\n1. E is independent of distance\n2. E ∝ 1/r²\n3. E ∝ 1/r\n4. E ∝ r", "explanation": "Point charge: E = kq/r² → A-2. Infinite line charge: E = λ/(2πε₀r) → B-3. Infinite plane sheet: E = σ/(2ε₀), independent of distance → C-1. Inside solid sphere: E = kQr/R³ → D-4.", "correct_answer": "B", "concept_tags": ["field-dependence", "charge-distributions", "distance-variation"], "payload": {"question_id": "cuet-phy-elec-gauss-29", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-3, C-1, D-4", "is_correct": true}, {"key": "C", "text": "A-3, B-2, C-4, D-1", "is_correct": false}, {"key": "D", "text": "A-2, B-3, C-4, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. The line charge field varies as 1/r, while the plane sheet field is distance-independent.", "misconception": "Confusing the distance dependence of line charge and plane sheet fields"}, {"option_key": "C", "hint": "This assigns 1/r to the point charge and 1/r² to the line charge, which is reversed. Point charge field goes as 1/r².", "misconception": "Swapping point charge and line charge distance dependence"}, {"option_key": "D", "hint": "This assigns E ∝ r to the plane sheet and distance-independent to the solid sphere interior, which is reversed.", "misconception": "Confusing plane sheet field with solid sphere interior field"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the Gaussian surface choices in Column I with their corresponding charge distribution applications in Column II:\n\nColumn I:\nA. Spherical Gaussian surface\nB. Cylindrical Gaussian surface (axis along the charge)\nC. Cylindrical Gaussian surface (pillbox straddling the surface)\nD. Any arbitrary closed surface\n\nColumn II:\n1. Infinite plane sheet of charge\n2. Uniformly charged sphere (solid or hollow)\n3. Infinitely long straight charged wire\n4. Verifying Gauss''s law for net enclosed charge", "explanation": "A spherical Gaussian surface exploits the spherical symmetry of a charged sphere → A-2. A coaxial cylinder exploits the cylindrical symmetry of an infinite wire → B-3. A pillbox straddles an infinite plane sheet to find its field → C-1. Any arbitrary closed surface can verify Gauss''s law for enclosed charge → D-4.", "correct_answer": "C", "concept_tags": ["gaussian-surface-choice", "symmetry", "gauss-law-application"], "payload": {"question_id": "cuet-phy-elec-gauss-30", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-3, B-2, C-1, D-4", "is_correct": false}, {"key": "C", "text": "A-2, B-3, C-1, D-4", "is_correct": true}, {"key": "D", "text": "A-1, B-3, C-2, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps B and C. The coaxial cylinder (B) is used for an infinite wire (3), and the pillbox (C) is used for a plane sheet (1).", "misconception": "Confusing the Gaussian surface for wire and plane sheet"}, {"option_key": "B", "hint": "This swaps A and B. A spherical surface is used for a sphere (2), not for a wire. A cylinder is used for a wire (3).", "misconception": "Using spherical surface for wire and cylindrical for sphere"}, {"option_key": "D", "hint": "This assigns a spherical surface to a plane sheet. The correct choice for a plane sheet is a pillbox (small cylinder straddling the sheet).", "misconception": "Using spherical Gaussian surface for a plane geometry"}]}}]'::jsonb, 'deploy-2026-03-05-b04');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electric flux is a scalar quantity.", "explanation": "TRUE. Electric flux Φ = ∮E·dA is the dot product of two vectors (E and dA), which yields a scalar. Flux can be positive, negative, or zero, but it has no direction — it is a scalar.", "correct_answer": "A", "concept_tags": ["flux-scalar", "dot-product"], "payload": {"question_id": "cuet-phy-elec-gauss-31", "subtopic": "Properties of electric flux", "topic_name": "Gauss''s Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Flux is the dot product E·A, and a dot product always yields a scalar. It is not a vector.", "misconception": "Confusing flux (scalar from dot product) with a vector quantity"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Gauss''s law is applicable to any closed surface, regardless of its shape, as long as the surface is closed.", "explanation": "This statement is TRUE. Gauss''s law (∮E·dA = q_enclosed/ε₀) is valid for any closed surface (Gaussian surface), irrespective of its shape or size. However, to simplify calculations, we choose surfaces that exploit the symmetry of the charge distribution.", "correct_answer": "A", "concept_tags": ["gauss-law", "closed-surface", "generality"], "payload": {"question_id": "cuet-phy-elec-gauss-32", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Gauss''s law is a fundamental theorem valid for all closed surfaces. We choose symmetric surfaces for convenience, but the law holds for any closed surface.", "misconception": "Thinking Gauss''s law only works for symmetric surfaces"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "If the electric flux through a closed surface is zero, there must be no charges anywhere inside it.", "explanation": "FALSE. Zero net flux means the net enclosed charge is zero (by Gauss''s law: Φ = q_net/ε₀ = 0). But this could be because there are equal amounts of positive and negative charge inside (e.g., a dipole), not necessarily because there are no charges at all.", "correct_answer": "B", "concept_tags": ["zero-flux", "net-charge", "dipole-enclosed"], "payload": {"question_id": "cuet-phy-elec-gauss-33", "subtopic": "Interpretation of Gauss''s law", "topic_name": "Gauss''s Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A dipole (+q and −q) inside a closed surface gives zero net flux but contains charges. Zero flux means zero NET charge, not zero charge.", "misconception": "Confusing zero net charge with no charges present"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "true-false", "difficulty": "easy", "question_text": "If the net electric flux through a closed surface is zero, it necessarily means that no charge exists inside the surface.", "explanation": "This statement is FALSE. Zero net flux means the net enclosed charge is zero, but this does not mean no charges exist inside. Equal amounts of positive and negative charge can be enclosed, with their effects cancelling to give zero net flux. For example, a dipole inside a closed surface gives zero net flux.", "correct_answer": "B", "concept_tags": ["gauss-law", "zero-flux", "net-charge"], "payload": {"question_id": "cuet-phy-elec-gauss-34", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Zero flux only implies zero NET charge. A surface enclosing a dipole (+q and −q) has zero net flux but contains charges.", "misconception": "Equating zero net flux with absence of all charges"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The SI unit of electric flux is ______.", "explanation": "Electric flux Φ = E·A has units of (N/C) × m² = N·m²/C. This can also be written as V·m (volt-metre), since V = J/C = N·m/C, giving V·m = N·m²/C.", "correct_answer": "D", "concept_tags": ["electric-flux", "SI-units", "definition"], "payload": {"question_id": "cuet-phy-elec-gauss-35", "subtopic": "Electric flux units", "topic_name": "Gauss''s Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "N/C", "is_correct": false}, {"key": "B", "text": "C/m²", "is_correct": false}, {"key": "C", "text": "V/m", "is_correct": false}, {"key": "D", "text": "N·m²/C (or V·m)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "N/C is the unit of electric field, not electric flux. Flux = field × area, so it has an extra m² factor.", "misconception": "Confusing electric field with electric flux"}, {"option_key": "B", "hint": "C/m² is the unit of surface charge density (σ), not flux.", "misconception": "Confusing flux with charge density"}, {"option_key": "C", "hint": "V/m is another unit of electric field (equivalent to N/C). Flux has units of V·m, not V/m.", "misconception": "Confusing V/m (field) with V·m (flux)"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The electric field inside a conductor in electrostatic equilibrium is _____.", "explanation": "In electrostatic equilibrium, free charges in a conductor have settled and there is no current. If there were any non-zero internal field, free electrons would move (contradicting equilibrium). Therefore E = 0 everywhere inside a conductor in electrostatic equilibrium.", "correct_answer": "A", "concept_tags": ["conductor-field", "electrostatic-equilibrium"], "payload": {"question_id": "cuet-phy-elec-gauss-36", "subtopic": "Conductors in electrostatics", "topic_name": "Gauss''s Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "σ/ε₀", "is_correct": false}, {"key": "C", "text": "σ/(2ε₀)", "is_correct": false}, {"key": "D", "text": "Infinity", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "σ/ε₀ is the field just outside the conductor surface, not inside. Inside, the field is always zero in equilibrium.", "misconception": "Confusing surface field with internal field"}, {"option_key": "C", "hint": "σ/(2ε₀) is for a non-conducting sheet. Inside a conductor, E = 0 because free charges redistribute to cancel any internal field.", "misconception": "Using sheet formula for conductor interior"}, {"option_key": "D", "hint": "The field is zero, not infinite. Free charges arrange themselves to perfectly shield the interior.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["NEET", "CUET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A physicist constructs a hollow metallic sphere of radius 15 cm and places a charge of +8 μC at its centre using an insulating support. She then measures the electric field at various distances from the centre.\n\nWhat is the electric field at a distance of 10 cm from the centre (inside the sphere)?", "explanation": "This is a hollow conducting sphere with a charge at its centre. By Gauss''s law, using a spherical Gaussian surface of radius r = 10 cm (inside the metallic shell), the enclosed charge is +8 μC (the charge at the centre). Wait — but the inner surface of the conductor will have −8 μC induced on it, and the Gaussian surface at r = 10 cm encloses only the +8 μC point charge (the inner surface is at R = 15 cm). So E = kQ/r² = 9 × 10⁹ × 8 × 10⁻⁶/(0.1)² = 72 × 10³/0.01 = 7.2 × 10⁶ N/C.", "correct_answer": "D", "concept_tags": ["hollow-sphere", "gauss-law", "charge-at-centre", "induced-charge"], "payload": {"question_id": "cuet-phy-elec-gauss-37", "subtopic": "", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "3.6 × 10⁶ N/C", "is_correct": false}, {"key": "C", "text": "3.2 × 10⁶ N/C", "is_correct": false}, {"key": "D", "text": "7.2 × 10⁶ N/C", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The field would be zero inside the conductor material itself, but the space between the centre charge and the inner surface is not part of the conductor. In this region, the field from the point charge exists.", "misconception": "Confusing the cavity region with the conductor material"}, {"option_key": "B", "hint": "3.6 × 10⁶ N/C might result from using r = 0.1 m but halving the charge or making a calculation error.", "misconception": "Arithmetic error in applying Coulomb''s law"}, {"option_key": "C", "hint": "3.2 × 10⁶ N/C would result from using R = 15 cm instead of r = 10 cm. The field must be evaluated at the observation point, not the shell radius.", "misconception": "Using shell radius instead of observation distance"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A thin metallic spherical shell of radius R = 0.1 m carries a charge Q = +4 μC. A point charge q = −2 μC is placed at the centre. Using Gauss''s law, determine the electric field at a distance r = 0.2 m from the centre and the charge on the inner surface of the shell.", "explanation": "Inner surface charge: By Gauss''s law, take a Gaussian sphere just inside the shell (r slightly < R). The enclosed charge is q = −2 μC. Since E = 0 inside a conductor, the flux is zero, so the charge on the inner surface must be +2 μC (to make enclosed charge zero for a Gaussian surface inside the metal). Outer surface: total charge = Q + q_inner = 4 − 2 = 2 μC on the outer surface. At r = 0.2 m: Enclosed charge = q + Q = −2 + 4 = 2 μC. E = kQ_enc/r² = 9 × 10⁹ × 2 × 10⁻⁶ / (0.2)² = 18000/0.04 = 4.5 × 10⁵ N/C, outward.", "correct_answer": "B", "concept_tags": ["shell-with-charge", "induced-charge", "gauss-law-numerical"], "payload": {"question_id": "cuet-phy-elec-gauss-38", "subtopic": "Conductors with internal charges", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "E = 4.5 × 10⁵ N/C outward; inner surface charge = −2 μC", "is_correct": false}, {"key": "B", "text": "E = 4.5 × 10⁵ N/C outward; inner surface charge = +2 μC", "is_correct": true}, {"key": "C", "text": "E = 9 × 10⁵ N/C outward; inner surface charge = +2 μC", "is_correct": false}, {"key": "D", "text": "E = 4.5 × 10⁵ N/C inward; inner surface charge = +4 μC", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field is correct, but the inner surface charge must be +2 μC (not −2 μC). The inner surface acquires a charge opposite to q to ensure E = 0 inside the metal.", "misconception": "Thinking the inner surface has the same sign as the internal charge"}, {"option_key": "C", "hint": "9 × 10⁵ N/C is double the correct value. The enclosed charge at r = 0.2 m is (−2 + 4) = +2 μC, not +4 μC.", "misconception": "Using Q alone instead of Q + q for enclosed charge outside"}, {"option_key": "D", "hint": "The direction is outward (not inward) since the net enclosed charge is positive (+2 μC). Also, inner surface charge is +2 μC, not +4 μC.", "misconception": "Using wrong direction and charge value"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following charge distributions in order of how their electric field decreases with distance (slowest to fastest decrease):\n\n1. Infinite line charge (E ∝ ?)\n2. Point charge (E ∝ ?)\n3. Electric dipole (E ∝ ?)\n4. Infinite plane sheet (E ∝ ?)", "explanation": "The distance dependences are: Infinite plane sheet: E = σ/(2ε₀) ∝ r⁰ (constant, slowest decrease). Infinite line charge: E = λ/(2πε₀r) ∝ 1/r. Point charge: E = kQ/r² ∝ 1/r². Electric dipole: E ∝ 1/r³ (fastest decrease). Order from slowest to fastest: 4 (r⁰) → 1 (1/r) → 2 (1/r²) → 3 (1/r³).", "correct_answer": "C", "concept_tags": ["field-dependence", "distance-comparison", "ordering"], "payload": {"question_id": "cuet-phy-elec-gauss-39", "subtopic": "Comparing charge distributions", "topic_name": "Gauss''s Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 → 2 → 3 → 4", "is_correct": false}, {"key": "B", "text": "3 → 2 → 1 → 4", "is_correct": false}, {"key": "C", "text": "4 → 1 → 2 → 3", "is_correct": true}, {"key": "D", "text": "4 → 2 → 1 → 3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This starts with line charge (1/r) but the infinite plane (constant field) decreases even more slowly. The plane must come first.", "misconception": "Forgetting that a plane sheet has constant field"}, {"option_key": "B", "hint": "This starts with dipole (1/r³), which has the fastest decrease. The question asks for slowest to fastest.", "misconception": "Reversing the order"}, {"option_key": "D", "hint": "This swaps items 1 and 2. The line charge (1/r) decreases slower than the point charge (1/r²), so line charge comes before point charge.", "misconception": "Confusing line charge (1/r) with point charge (1/r²) dependence"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-gauss", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following steps in the correct order for deriving the electric field inside a uniformly charged non-conducting solid sphere of radius R at distance r from the centre (r < R):", "explanation": "Step 1: Choose the Gaussian surface (sphere of radius r < R). Step 2: Write Gauss''s law. Step 3: Use the spherical symmetry to simplify the left side to E × 4πr². Step 4: Calculate the charge enclosed within radius r. Step 5: Equate and solve for E. The key insight is that only the charge within radius r contributes, giving E ∝ r (linear increase inside).", "correct_answer": "C", "concept_tags": ["gauss-law-derivation", "solid-sphere", "systematic-method"], "payload": {"question_id": "cuet-phy-elec-gauss-40", "subtopic": "Field inside a solid sphere", "topic_name": "Gauss''s Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "1 → 2 → 3 → 4 → 5", "is_correct": false}, {"key": "B", "text": "3 → 1 → 4 → 2 → 5", "is_correct": false}, {"key": "C", "text": "1 → 3 → 4 → 2 → 5", "is_correct": true}, {"key": "D", "text": "1 → 4 → 3 → 2 → 5", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This calculates the enclosed charge (step 2) before writing Gauss''s law (step 3). It''s more logical to state the law first, then evaluate each side.", "misconception": "Calculating charge before stating the principle"}, {"option_key": "B", "hint": "You should choose the Gaussian surface (step 1) before applying Gauss''s law (step 3). You can''t apply the law without first defining the surface.", "misconception": "Applying Gauss''s law before choosing the surface"}, {"option_key": "D", "hint": "Using symmetry (step 4) simplifies the LHS of Gauss''s law, so step 3 (writing the law) should come before step 4.", "misconception": "Simplifying the integral before stating the equation"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric potential due to a positive point charge:", "explanation": "V = kq/r. For a positive charge (q > 0), V is positive at all points and decreases with increasing distance, approaching zero at infinity. It never becomes negative or zero at a finite distance.", "correct_answer": "B", "concept_tags": ["potential-sign", "point-charge", "distance-dependence"], "payload": {"question_id": "cuet-phy-elec-potential-01", "subtopic": "Potential due to a point charge", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "Is always negative", "is_correct": false}, {"key": "B", "text": "Is always positive and decreases with distance", "is_correct": true}, {"key": "C", "text": "Can be positive or negative depending on distance", "is_correct": false}, {"key": "D", "text": "Is zero at all points", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Negative potential occurs for negative charges. For positive q, V = kq/r is always positive.", "misconception": "Confusing sign of potential with sign of charge"}, {"option_key": "C", "hint": "V = kq/r with positive q is always positive regardless of r. It only changes in magnitude, not sign.", "misconception": "Thinking distance can change the sign of potential"}, {"option_key": "D", "hint": "V = 0 only at r → ∞. At any finite distance, a point charge creates a non-zero potential.", "misconception": "Confusing zero field line with zero potential"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Equipotential surfaces due to a uniform electric field are:", "explanation": "In a uniform field E along x, V = −Ex + constant. Surfaces of constant V require x = constant, which are planes perpendicular to E. These planes are equally spaced (for equal voltage intervals) and always perpendicular to the field lines.", "correct_answer": "A", "concept_tags": ["equipotential", "uniform-field", "plane-surfaces"], "payload": {"question_id": "cuet-phy-elec-potential-02", "subtopic": "Equipotential surfaces", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "Planes perpendicular to the field direction", "is_correct": true}, {"key": "B", "text": "Concentric spheres", "is_correct": false}, {"key": "C", "text": "Planes parallel to the field direction", "is_correct": false}, {"key": "D", "text": "Concentric cylinders", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Concentric spheres are equipotential surfaces for a point charge, not for a uniform field.", "misconception": "Confusing point charge geometry with uniform field geometry"}, {"option_key": "C", "hint": "Parallel to the field means along the field direction, where potential changes. Equipotential must be perpendicular to E.", "misconception": "Confusing parallel with perpendicular"}, {"option_key": "D", "hint": "Concentric cylinders are equipotential surfaces for an infinite line charge, not a uniform field.", "misconception": "Confusing line charge geometry with uniform field"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The work done in moving a unit positive charge from point A to point B in an electric field is equal to:", "explanation": "Work done per unit charge in moving from A to B is the potential difference: W/q = V_A − V_B. So for a unit positive charge (q = 1), W = V_A − V_B. The work is positive when moving from higher to lower potential (field does work), and negative when moving against the field.", "correct_answer": "C", "concept_tags": ["work-done", "potential-difference", "unit-charge"], "payload": {"question_id": "cuet-phy-elec-potential-03", "subtopic": "Potential difference and work", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "V_B − V_A", "is_correct": false}, {"key": "B", "text": "V_A × V_B", "is_correct": false}, {"key": "C", "text": "V_A − V_B", "is_correct": true}, {"key": "D", "text": "V_A + V_B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "V_B − V_A gives work done against the field (or the negative of work done by the field). The work done by the field is V_A − V_B.", "misconception": "Reversing the sign convention for work"}, {"option_key": "B", "hint": "Product of potentials has no physical meaning in this context. Work involves the difference, not the product.", "misconception": null}, {"option_key": "D", "hint": "Sum of potentials has no physical meaning for work calculation. Work = potential difference = V_A − V_B.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric potential at the centre of a uniformly charged conducting spherical shell of radius R and charge Q is:", "explanation": "For a conducting shell, V at any point inside or on the surface = kQ/R (constant). At the centre, V = kQ/R, not zero. The electric field is zero inside, but the potential is constant and equals the surface potential.", "correct_answer": "D", "concept_tags": ["conducting-shell", "potential-inside", "constant-potential"], "payload": {"question_id": "cuet-phy-elec-potential-04", "subtopic": "Potential of a charged shell", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "kQ/R²", "is_correct": false}, {"key": "C", "text": "Infinity", "is_correct": false}, {"key": "D", "text": "kQ/R", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "E = 0 inside, but V ≠ 0. The potential inside is constant and equal to the surface value kQ/R. Don''t confuse zero field with zero potential.", "misconception": "Thinking zero electric field means zero potential"}, {"option_key": "B", "hint": "kQ/R² has dimensions of electric field (N/C), not potential (V). Potential is kQ/R.", "misconception": "Confusing field formula with potential formula"}, {"option_key": "C", "hint": "Potential is infinite only at the location of a true point charge (r = 0). A shell has charge distributed on its surface, not at the centre.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric potential at a distance r from a point charge q is given by:", "explanation": "The electric potential due to a point charge q at a distance r is V = kq/r = q/(4πε₀r). This is a scalar quantity and can be positive or negative depending on the sign of the charge.", "correct_answer": "A", "concept_tags": ["electric potential", "point charge", "Coulomb constant"], "payload": {"question_id": "cuet-phy-elec-potential-05", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "V = kq/r", "is_correct": true}, {"key": "B", "text": "V = kq/r²", "is_correct": false}, {"key": "C", "text": "V = kq²/r", "is_correct": false}, {"key": "D", "text": "V = kr/q", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "kq/r² is the expression for electric field magnitude, not electric potential. Potential varies as 1/r, not 1/r².", "misconception": "Confusing electric field with electric potential"}, {"option_key": "C", "hint": "The charge appears to the first power in the potential formula, not squared.", "misconception": null}, {"option_key": "D", "hint": "This expression has incorrect dimensional analysis and does not represent any standard electrostatic quantity.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Electric potential is a scalar quantity. What is the SI unit of electric potential?", "explanation": "The SI unit of electric potential is the volt (V). One volt is defined as one joule per coulomb (1 V = 1 J/C). It represents the potential energy per unit charge at a point in the electric field.", "correct_answer": "B", "concept_tags": ["electric potential", "SI unit", "volt"], "payload": {"question_id": "cuet-phy-elec-potential-06", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "Newton per coulomb (N/C)", "is_correct": false}, {"key": "B", "text": "Volt (V)", "is_correct": true}, {"key": "C", "text": "Coulomb per metre (C/m)", "is_correct": false}, {"key": "D", "text": "Joule (J)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Newton per coulomb (N/C) is the unit of electric field intensity, not electric potential.", "misconception": "Confusing units of electric field and electric potential"}, {"option_key": "C", "hint": "Coulomb per metre is not a standard unit for any common electrostatic quantity.", "misconception": null}, {"option_key": "D", "hint": "Joule is the unit of energy. Electric potential is energy per unit charge, so its unit is J/C = V, not just J.", "misconception": "Confusing potential energy with potential"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The work done in moving a charge of 5 μC between two points having a potential difference of 20 V is:", "explanation": "The work done in moving a charge q through a potential difference ΔV is W = qΔV. Here q = 5 μC = 5 × 10⁻⁶ C and ΔV = 20 V. So W = 5 × 10⁻⁶ × 20 = 100 × 10⁻⁶ J = 100 μJ = 1 × 10⁻⁴ J.", "correct_answer": "C", "concept_tags": ["work done", "potential difference", "charge"], "payload": {"question_id": "cuet-phy-elec-potential-07", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "1 × 10⁻³ J", "is_correct": false}, {"key": "B", "text": "4 × 10⁻⁶ J", "is_correct": false}, {"key": "C", "text": "1 × 10⁻⁴ J", "is_correct": true}, {"key": "D", "text": "2.5 × 10⁻⁷ J", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 × 10⁻³ J would result from using 50 μC instead of 5 μC, which is ten times the given charge.", "misconception": null}, {"option_key": "B", "hint": "4 × 10⁻⁶ J does not follow from multiplying 5 × 10⁻⁶ C by 20 V.", "misconception": null}, {"option_key": "D", "hint": "2.5 × 10⁻⁷ J would result from dividing charge by potential difference instead of multiplying.", "misconception": "Dividing instead of multiplying q and V"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric potential V in a region is given by V = 3x² + 4y − 2z (in volts, distances in metres). The electric field at the origin is:", "explanation": "E = −∇V. E_x = −∂V/∂x = −6x. E_y = −∂V/∂y = −4. E_z = −∂V/∂z = +2. At origin (x=0, y=0, z=0): E = (0, −4, 2) V/m. Magnitude = √(0 + 16 + 4) = √20 = 2√5 V/m.", "correct_answer": "B", "concept_tags": ["gradient", "electric-field-from-potential", "partial-derivatives"], "payload": {"question_id": "cuet-phy-elec-potential-08", "subtopic": "Relation between E and V", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "(0, 4, −2) V/m", "is_correct": false}, {"key": "B", "text": "(0, −4, 2) V/m", "is_correct": true}, {"key": "C", "text": "(6, −4, 2) V/m", "is_correct": false}, {"key": "D", "text": "(0, −4, −2) V/m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "You forgot the negative sign: E = −∇V, not +∇V. The correct y-component is −(+4) = −4, not +4.", "misconception": "Forgetting the negative sign in E = −∇V"}, {"option_key": "C", "hint": "E_x = −6x, and at the origin x = 0, so E_x = 0, not 6.", "misconception": "Evaluating the derivative but not substituting x = 0"}, {"option_key": "D", "hint": "E_z = −∂V/∂z = −(−2) = +2, not −2. The derivative of −2z with respect to z is −2, and E_z = −(−2) = +2.", "misconception": "Sign error in double negative"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two point charges +q and −2q are separated by distance d. The point on the line joining them where the electric potential is zero (other than at infinity) lies:", "explanation": "Let the zero-potential point be at distance x from +q (towards −2q). Then kq/x − 2kq/(d−x) = 0, giving d − x = 2x, so x = d/3. This point lies between the charges at distance d/3 from +q. There''s also an external zero-potential point, but between the charges is the standard answer for the ''other than infinity'' condition.", "correct_answer": "A", "concept_tags": ["zero-potential", "superposition", "two-charges"], "payload": {"question_id": "cuet-phy-elec-potential-09", "subtopic": "Potential due to charge system", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "Between the charges, at distance d/3 from +q", "is_correct": true}, {"key": "B", "text": "Between the charges, at the midpoint", "is_correct": false}, {"key": "C", "text": "Outside the charges, beyond −2q", "is_correct": false}, {"key": "D", "text": "There is no such point", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "At the midpoint, V = kq/(d/2) − 2kq/(d/2) = 2kq/d − 4kq/d = −2kq/d ≠ 0. The unequal charges make the midpoint non-zero.", "misconception": "Assuming zero potential at midpoint for unequal charges"}, {"option_key": "C", "hint": "There is also a zero-potential point outside (beyond +q, at distance d from +q), but the question asks for the point on the line, and the primary solution between the charges is d/3.", "misconception": "Selecting the external solution without checking the internal one"}, {"option_key": "D", "hint": "Zero potential points always exist between unequal opposite-sign charges. Since potential is scalar, it smoothly transitions from positive (near +q) to negative (near −2q).", "misconception": "Thinking zero potential is impossible with unequal charges"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electrostatic potential energy of a system of three point charges q, 2q, and 3q placed at the vertices of an equilateral triangle of side a is:", "explanation": "U = k[q₁q₂/r₁₂ + q₂q₃/r₂₃ + q₁q₃/r₁₃]. All distances = a. U = k[(q)(2q)/a + (2q)(3q)/a + (q)(3q)/a] = k[2q² + 6q² + 3q²]/a = 11kq²/a.", "correct_answer": "C", "concept_tags": ["potential-energy", "three-charges", "triangle"], "payload": {"question_id": "cuet-phy-elec-potential-10", "subtopic": "Potential energy of charge system", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "6kq²/a", "is_correct": false}, {"key": "B", "text": "9kq²/a", "is_correct": false}, {"key": "C", "text": "11kq²/a", "is_correct": true}, {"key": "D", "text": "12kq²/a", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6kq²/a counts only one pair (2q × 3q). You need all three pairs: q·2q + 2q·3q + q·3q = 2 + 6 + 3 = 11.", "misconception": "Counting only the largest pair interaction"}, {"option_key": "B", "hint": "9kq²/a would arise from (1+2)(1+2) type error. The correct pairwise sum is 2 + 6 + 3 = 11.", "misconception": null}, {"option_key": "D", "hint": "12kq²/a could come from (q + 2q + 3q)²/(2a) = 36kq²/(2a). But potential energy is not calculated using total charge squared.", "misconception": "Using (total charge)² formula instead of pairwise sum"}]}}]'::jsonb, 'deploy-2026-03-05-b04');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the electric field in a region is zero, the electric potential in that region must be:", "explanation": "E = −dV/dr. If E = 0 everywhere in a region, then dV/dr = 0, meaning V is constant throughout. The constant can be any value (positive, negative, or zero), but it must be the same at all points in the region.", "correct_answer": "D", "concept_tags": ["zero-field", "constant-potential", "E-V-relation"], "payload": {"question_id": "cuet-phy-elec-potential-11", "subtopic": "Relation between E and V", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "Zero everywhere", "is_correct": false}, {"key": "B", "text": "Varying linearly with distance", "is_correct": false}, {"key": "C", "text": "Maximum at some point", "is_correct": false}, {"key": "D", "text": "Constant (but not necessarily zero)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Zero is one possible constant, but not the only one. Inside a charged conductor, E = 0 but V = kQ/R ≠ 0.", "misconception": "Thinking zero field implies zero potential"}, {"option_key": "B", "hint": "If V varied linearly, then E = −dV/dr would be a non-zero constant, contradicting E = 0.", "misconception": "Confusing constant field with zero field"}, {"option_key": "C", "hint": "A maximum implies V changes on either side, which requires a non-zero gradient (field).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The potential at a point P due to an electric dipole of moment p at distance r (r >> 2a) making angle θ with the dipole axis is:", "explanation": "The potential due to a dipole at a general point is V = kp cosθ/r². On the axial line (θ = 0°), V = kp/r². On the equatorial line (θ = 90°), V = 0. The potential follows an inverse-square law with distance (not inverse cube like the field).", "correct_answer": "A", "concept_tags": ["dipole-potential", "angular-dependence", "inverse-square"], "payload": {"question_id": "cuet-phy-elec-potential-12", "subtopic": "Potential due to a dipole", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "kp cosθ/r²", "is_correct": true}, {"key": "B", "text": "kp sinθ/r²", "is_correct": false}, {"key": "C", "text": "kp cosθ/r³", "is_correct": false}, {"key": "D", "text": "kp/r²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "sinθ would give zero on the axial line (θ = 0°) and maximum on the equatorial line — the exact opposite of what happens. Dipole potential uses cosθ.", "misconception": "Confusing cosθ with sinθ in dipole potential formula"}, {"option_key": "C", "hint": "1/r³ is the distance dependence of the dipole electric field, not the potential. Potential falls off as 1/r².", "misconception": "Confusing dipole field dependence with potential dependence"}, {"option_key": "D", "hint": "This omits the angular (cosθ) dependence. The dipole potential is not the same at all angles — it''s zero on the equatorial line.", "misconception": "Forgetting angular dependence of dipole potential"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two point charges +4 μC and −4 μC are placed 20 cm apart. The electric potential at the midpoint of the line joining the two charges is:", "explanation": "At the midpoint, the distance from each charge is 10 cm = 0.1 m. Potential due to +4 μC is V₁ = kq/r = 9 × 10⁹ × 4 × 10⁻⁶/0.1 = +3.6 × 10⁵ V. Potential due to −4 μC is V₂ = 9 × 10⁹ × (−4 × 10⁻⁶)/0.1 = −3.6 × 10⁵ V. Total V = V₁ + V₂ = 0.", "correct_answer": "A", "concept_tags": ["superposition of potential", "point charges", "midpoint"], "payload": {"question_id": "cuet-phy-elec-potential-13", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "3.6 × 10⁵ V", "is_correct": false}, {"key": "C", "text": "7.2 × 10⁵ V", "is_correct": false}, {"key": "D", "text": "−3.6 × 10⁵ V", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "3.6 × 10⁵ V is the potential due to only the positive charge. You must add the contribution from both charges.", "misconception": "Ignoring the contribution of the negative charge"}, {"option_key": "C", "hint": "7.2 × 10⁵ V would result from adding the magnitudes without considering the sign of the charges.", "misconception": "Treating potential as always positive like electric field magnitude"}, {"option_key": "D", "hint": "−3.6 × 10⁵ V is the potential due to only the negative charge; the positive charge contribution must also be included.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric potential at a point on the axial line of a short electric dipole at distance r from the centre is proportional to:", "explanation": "The potential due to a short electric dipole at a point on its axial line is V = kp cos θ/r², where θ = 0° for the axial line. Thus V = kp/r², which means V is proportional to 1/r². The potential falls off faster for a dipole compared to a point charge.", "correct_answer": "B", "concept_tags": ["electric dipole", "axial potential", "inverse square"], "payload": {"question_id": "cuet-phy-elec-potential-14", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "1/r", "is_correct": false}, {"key": "B", "text": "1/r²", "is_correct": true}, {"key": "C", "text": "1/r³", "is_correct": false}, {"key": "D", "text": "1/r⁴", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/r dependence is characteristic of the potential due to a point charge, not a dipole.", "misconception": "Confusing point charge potential with dipole potential"}, {"option_key": "C", "hint": "1/r³ dependence is characteristic of the electric field of a dipole, not the potential.", "misconception": "Confusing dipole electric field variation with dipole potential variation"}, {"option_key": "D", "hint": "No standard electrostatic quantity for a dipole varies as 1/r⁴ in the far-field approximation.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric potential at a point on the equatorial plane of a short electric dipole is:", "explanation": "On the equatorial plane of a dipole, the angle θ = 90°. The potential is V = kp cos θ/r² = kp cos 90°/r² = 0. The contributions from the positive and negative charges exactly cancel at every point on the equatorial plane.", "correct_answer": "C", "concept_tags": ["electric dipole", "equatorial potential", "zero potential"], "payload": {"question_id": "cuet-phy-elec-potential-15", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "Positive", "is_correct": false}, {"key": "B", "text": "Negative", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "Depends on the dipole moment", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Both charges are equidistant from any point on the equatorial plane, so the positive and negative potentials cancel exactly.", "misconception": null}, {"option_key": "B", "hint": "The negative charge does not dominate since it is at the same distance as the positive charge from any equatorial point.", "misconception": null}, {"option_key": "D", "hint": "While the individual potentials depend on dipole moment, their sum on the equatorial plane is always zero regardless of the dipole moment magnitude.", "misconception": "Thinking the result depends on dipole moment magnitude"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The relation between electric field E and electric potential V is given by E = −dV/dr. If V = 4x² volt (where x is in metres), the electric field at x = 1 m is:", "explanation": "Given V = 4x², the electric field component along x is E = −dV/dx = −d(4x²)/dx = −8x. At x = 1 m, E = −8(1) = −8 V/m. The magnitude is 8 V/m directed in the negative x-direction.", "correct_answer": "D", "concept_tags": ["relation between E and V", "potential gradient", "differentiation"], "payload": {"question_id": "cuet-phy-elec-potential-16", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "4 V/m in negative x-direction", "is_correct": false}, {"key": "B", "text": "4 V/m in positive x-direction", "is_correct": false}, {"key": "C", "text": "8 V/m in positive x-direction", "is_correct": false}, {"key": "D", "text": "8 V/m in negative x-direction", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4 V/m would result from forgetting to apply the power rule correctly during differentiation of 4x².", "misconception": "Incorrect differentiation of polynomial"}, {"option_key": "B", "hint": "The direction is wrong. E = −dV/dx gives a negative sign, indicating the field points in the negative x-direction.", "misconception": null}, {"option_key": "C", "hint": "While the magnitude 8 V/m is correct, the direction should be negative x since E = −dV/dx and dV/dx is positive.", "misconception": "Forgetting the negative sign in E = −dV/dr"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The potential at a point on the surface of a uniformly charged non-conducting solid sphere of radius R and total charge Q is V₀. The potential at a point at distance R/2 from the centre is:", "explanation": "Outside and on surface: V₀ = kQ/R. Inside (r < R): V = kQ(3R² − r²)/(2R³). At r = R/2: V = kQ(3R² − R²/4)/(2R³) = kQ(11R²/4)/(2R³) = 11kQ/(8R) = 11V₀/8. The potential inside a solid sphere is higher than the surface potential.", "correct_answer": "D", "concept_tags": ["solid-sphere-potential", "inside-potential", "non-conductor"], "payload": {"question_id": "cuet-phy-elec-potential-17", "subtopic": "Potential inside a solid sphere", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "V₀/2", "is_correct": false}, {"key": "B", "text": "V₀", "is_correct": false}, {"key": "C", "text": "3V₀/2", "is_correct": false}, {"key": "D", "text": "11V₀/8", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "V₀/2 would apply if V ∝ r (linear decrease), but the potential inside a solid sphere follows V = kQ(3R² − r²)/(2R³), not a linear law.", "misconception": "Assuming potential decreases linearly inside a solid sphere"}, {"option_key": "B", "hint": "V = V₀ would mean constant potential inside (as in a shell). For a solid sphere, the potential increases from surface toward the centre.", "misconception": "Confusing solid sphere with hollow shell"}, {"option_key": "C", "hint": "3V₀/2 is the potential at the centre (r = 0): V = kQ × 3R²/(2R³) = 3kQ/(2R) = 3V₀/2. At r = R/2, it''s less than this.", "misconception": "Using the centre value instead of calculating at r = R/2"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two concentric metallic shells of radii R and 2R carry charges Q and −2Q respectively. The potential at distance r = 3R from the centre is:", "explanation": "For r > 2R (outside both shells), both shells act as point charges at the centre. V = k(Q + (−2Q))/(3R) = k(−Q)/(3R) = −kQ/(3R). The potential depends on the total enclosed charge.", "correct_answer": "B", "concept_tags": ["concentric-shells", "superposition", "external-potential"], "payload": {"question_id": "cuet-phy-elec-potential-18", "subtopic": "Potential of concentric shells", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "kQ/(3R)", "is_correct": false}, {"key": "B", "text": "−kQ/(3R)", "is_correct": true}, {"key": "C", "text": "−3kQ/(2R)", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This ignores the −2Q on the outer shell. The net charge is Q + (−2Q) = −Q, not +Q.", "misconception": "Considering only the inner shell''s charge"}, {"option_key": "C", "hint": "−3kQ/(2R) might come from incorrectly adding potentials. At r = 3R: V = kQ/(3R) + k(−2Q)/(3R) = −kQ/(3R).", "misconception": "Using different distances for the two shells at an external point"}, {"option_key": "D", "hint": "Zero potential would require Q_net = 0, but Q + (−2Q) = −Q ≠ 0.", "misconception": "Thinking opposite charges on concentric shells cancel the potential"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A charge Q is distributed uniformly on a ring of radius R. A point charge −q is moved from infinity to the centre of the ring. The work done by the external agent is:", "explanation": "V at centre of ring = kQ/R (all charge elements on the ring are at distance R from the centre). Work done by external agent = Change in PE = (−q)(V_centre − V_∞) = (−q)(kQ/R − 0) = −kQq/R. The negative sign means the external agent does negative work (the field does positive work pulling −q toward the positive ring).", "correct_answer": "C", "concept_tags": ["ring-potential", "work-by-external-agent", "centre-potential"], "payload": {"question_id": "cuet-phy-elec-potential-19", "subtopic": "Work and potential energy", "topic_name": "Electric Potential", "bloom_level": "apply", "options": [{"key": "A", "text": "kQq/R", "is_correct": false}, {"key": "B", "text": "kQq/R²", "is_correct": false}, {"key": "C", "text": "−kQq/R", "is_correct": true}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Positive work would mean the agent pushes against the field. But −q is attracted to the positive ring, so the field does the work and the agent does negative work.", "misconception": "Getting the sign wrong — confusing work by field with work against field"}, {"option_key": "B", "hint": "kQq/R² has dimensions of force, not energy. Work = charge × potential, not charge × field.", "misconception": "Confusing potential (kQ/R) with field (kQ/R²)"}, {"option_key": "D", "hint": "Zero work implies no change in PE, but moving from infinity (V = 0) to the centre (V = kQ/R) definitely changes PE.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Eight identical point charges q are placed at the eight corners of a cube of side a. The electrostatic potential energy of the system is (k = 1/4πε₀):", "explanation": "A cube has 8 vertices. Total pairs = C(8,2) = 28. There are three types of pairs by distance: 12 edge pairs (distance a), 12 face-diagonal pairs (distance a√2), and 4 body-diagonal pairs (distance a√3). Total PE = kq²[12/a + 12/(a√2) + 4/(a√3)] = (kq²/a)[12 + 12/√2 + 4/√3] = (kq²/a)[12 + 6√2 + 4√3/3].", "correct_answer": "D", "concept_tags": ["potential energy of system", "cube arrangement", "multiple charge pairs"], "payload": {"question_id": "cuet-phy-elec-potential-20", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "analyze", "options": [{"key": "A", "text": "(kq²/a)(12 + 6√2)", "is_correct": false}, {"key": "B", "text": "(kq²/a)(24 + 12√2 + 4√3)", "is_correct": false}, {"key": "C", "text": "(kq²/a)(12 + 12√2 + 4√3)", "is_correct": false}, {"key": "D", "text": "(kq²/a)(12 + 6√2 + 4√3/3)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This expression omits the 4 body-diagonal pairs entirely. A cube has edge, face-diagonal, and body-diagonal pairs — all must be included.", "misconception": "Forgetting body-diagonal pairs in a cube"}, {"option_key": "B", "hint": "The coefficients 24 and 12 are twice the actual number of edge and face-diagonal pairs. There are 12 edges and 12 face diagonals, not 24 and 12.", "misconception": "Double-counting pairs"}, {"option_key": "C", "hint": "The face-diagonal contribution should be 12/(a√2) = 6√2·(kq²/a), not 12√2. Also 4/√3 = 4√3/3, not 4√3.", "misconception": "Error in rationalizing denominators"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): No work is done in moving a charge along an equipotential surface.\nReason (R): The electric field is always perpendicular to the equipotential surface.", "explanation": "Both A and R are true, and R correctly explains A. Since E ⊥ equipotential surface, the component of E along the surface is zero. Therefore, force on charge along the surface is zero, and work W = F·d = 0. The perpendicularity is what ensures zero work.", "correct_answer": "A", "concept_tags": ["equipotential", "zero-work", "perpendicular-field"], "payload": {"question_id": "cuet-phy-elec-potential-25", "subtopic": "Equipotential surfaces", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: because E is perpendicular to the surface, the force component along the surface is zero, hence zero work.", "misconception": "Not connecting the perpendicularity with zero work"}, {"option_key": "C", "hint": "R is correct — E is always perpendicular to equipotential surfaces. This is a fundamental property derived from E = −∇V.", "misconception": null}, {"option_key": "D", "hint": "A is correct — since potential is constant on an equipotential surface, ΔV = 0, so W = qΔV = 0.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The electric field is always perpendicular to the equipotential surface at every point.\nReason (R): No work is done in moving a charge along an equipotential surface.", "explanation": "Both the assertion and the reason are correct. If the electric field had a component along the equipotential surface, work would be done in moving a charge along the surface, contradicting the definition of an equipotential surface. Hence R correctly explains A — the perpendicularity ensures zero work along the surface.", "correct_answer": "A", "concept_tags": ["equipotential surface", "electric field direction", "work done"], "payload": {"question_id": "cuet-phy-elec-potential-26", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains why E must be perpendicular — if E had a tangential component, work would be done along the surface, violating the equipotential condition.", "misconception": "Not recognizing the causal link between zero work and perpendicularity"}, {"option_key": "C", "hint": "R is indeed correct; by definition, no work is done in moving a charge on an equipotential surface since ΔV = 0.", "misconception": null}, {"option_key": "D", "hint": "A is a well-established fact in electrostatics — the electric field lines are always normal to equipotential surfaces.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The potential at the centre of a uniformly charged non-conducting solid sphere is 1.5 times the potential at its surface.\nReason (R): The electric field inside a uniformly charged solid sphere is proportional to the distance from the centre.", "explanation": "Both A and R are true, and R is the correct explanation of A. V_centre = 3kQ/(2R) = 1.5 × kQ/R = 1.5 V_surface (A is true). R is true: E_inside = ρr/(3ε₀) ∝ r. R explains A because integrating this linear field from surface to centre gives the extra potential: V_centre − V_surface = ∫₀ᴿ E dr = kQ/(2R), leading to V_centre = 3kQ/(2R).", "correct_answer": "A", "concept_tags": ["solid-sphere", "centre-potential", "linear-field"], "payload": {"question_id": "cuet-phy-elec-potential-27", "subtopic": "Potential inside solid sphere", "topic_name": "Electric Potential", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R explains A directly — the 1.5 factor arises from integrating E ∝ r from the surface inward. The linear field profile is the reason for the specific ratio.", "misconception": "Not recognizing that the field profile determines the potential profile"}, {"option_key": "C", "hint": "R is correct — inside a uniformly charged solid sphere, E = ρr/(3ε₀), which is indeed proportional to r.", "misconception": null}, {"option_key": "D", "hint": "A is correct — V_centre = kQ(3R²)/(2R³) = 3kQ/(2R) = 1.5 × kQ/R = 1.5 V_surface.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The electrostatic potential energy of two like charges is positive.\nReason (R): Electric potential is always positive in the region surrounding a positive charge.", "explanation": "The assertion is correct: for two like charges (both positive or both negative), U = kq₁q₂/r is positive since the product q₁q₂ is positive. The reason is also correct: the potential around a positive charge is indeed positive (V = kq/r > 0 when q > 0). However, R does not explain A because A applies to both like positive and like negative charges, and the positivity of PE comes from the product of charges, not from the potential of a single charge.", "correct_answer": "B", "concept_tags": ["potential energy sign", "like charges", "electric potential sign"], "payload": {"question_id": "cuet-phy-elec-potential-28", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are independently true, R does not explain A. Two negative charges also have positive PE, but R talks about potential near positive charges only.", "misconception": "Assuming any two correct statements must be causally related"}, {"option_key": "C", "hint": "R is a correct statement — the potential around a positive point charge is indeed positive at all points.", "misconception": null}, {"option_key": "D", "hint": "A is correct — like charges (++ or −−) always give a positive product q₁q₂, making U = kq₁q₂/r positive.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following physical situations (Column I) with the corresponding electric potential (Column II):\n\nColumn I:\nA. Inside a uniformly charged spherical shell\nB. At the surface of a uniformly charged spherical shell of radius R\nC. At a distance 2R from the centre of a uniformly charged spherical shell\nD. At infinity\n\nColumn II:\n1. Zero\n2. kQ/R\n3. kQ/2R\n4. kQ/R (same as at surface)", "explanation": "Inside the shell (A), the potential is constant and equal to the surface potential: kQ/R, so A→4. At the surface (B), V = kQ/R, so B→2. At distance 2R (C), V = kQ/2R, so C→3. At infinity (D), V = 0, so D→1.", "correct_answer": "C", "concept_tags": ["spherical shell potential", "potential variation", "matching"], "payload": {"question_id": "cuet-phy-elec-potential-29", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "C", "text": "A-4, B-2, C-3, D-1", "is_correct": true}, {"key": "D", "text": "A-3, B-2, C-4, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-1 implies zero potential inside the shell, which is incorrect. The potential inside is constant and equal to the surface potential kQ/R.", "misconception": "Confusing zero electric field inside shell with zero potential"}, {"option_key": "B", "hint": "A-2 and B-4 both give kQ/R but the match labels are swapped incorrectly in the list structure.", "misconception": null}, {"option_key": "D", "hint": "A-3 would give kQ/2R inside the shell, which is wrong. The potential inside is kQ/R, not kQ/2R.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following quantities (Column I) with their distance dependence from a point charge (Column II):\n\nColumn I:\nA. Electric field due to point charge\nB. Electric potential due to point charge\nC. Electric field due to dipole (far field)\nD. Electric potential due to dipole (far field)\n\nColumn II:\n1. ∝ 1/r\n2. ∝ 1/r²\n3. ∝ 1/r³\n4. ∝ 1/r⁴", "explanation": "Electric field due to a point charge E = kq/r², so A→2. Electric potential due to a point charge V = kq/r, so B→1. Electric field due to a dipole varies as 1/r³, so C→3. Electric potential due to a dipole varies as 1/r², so D→2. Hence the correct matching is A-2, B-1, C-3, D-2.", "correct_answer": "B", "concept_tags": ["distance dependence", "point charge", "dipole", "field and potential"], "payload": {"question_id": "cuet-phy-elec-potential-30", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-3, D-2", "is_correct": true}, {"key": "C", "text": "A-2, B-1, C-4, D-3", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-4, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A-1 would mean E ∝ 1/r for a point charge, but the correct dependence is E ∝ 1/r² (Coulomb''s law).", "misconception": "Confusing potential and field dependence for point charge"}, {"option_key": "C", "hint": "C-4 would mean dipole field varies as 1/r⁴, which is incorrect. Dipole field varies as 1/r³.", "misconception": null}, {"option_key": "D", "hint": "A-1 and B-2 are swapped — field goes as 1/r² and potential goes as 1/r for a point charge.", "misconception": "Mixing up field and potential dependencies"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electric potential is a scalar quantity.", "explanation": "TRUE. Electric potential V = W/q (work per unit charge) is a scalar. Unlike the electric field (which is a vector), potential has no direction — it has only magnitude (positive, negative, or zero). The scalar nature makes superposition of potentials simpler than superposition of fields.", "correct_answer": "A", "concept_tags": ["potential-scalar", "scalar-quantity"], "payload": {"question_id": "cuet-phy-elec-potential-31", "subtopic": "Nature of electric potential", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Potential is defined as work/charge (W/q), both of which are scalars. A scalar divided by a scalar is a scalar, not a vector.", "misconception": "Confusing electric potential (scalar) with electric field (vector)"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The electric potential decreases along the direction of the electric field.", "explanation": "TRUE. E = −dV/dr implies that V decreases in the direction of E. The electric field points from higher potential to lower potential. This is analogous to a ball rolling downhill — the gravitational field points in the direction of decreasing gravitational potential.", "correct_answer": "A", "concept_tags": ["potential-decrease", "field-direction", "gradient"], "payload": {"question_id": "cuet-phy-elec-potential-32", "subtopic": "E-V relationship", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "From E = −dV/dr, if E > 0 in some direction, then dV/dr < 0 in that direction, meaning V decreases. The statement is true.", "misconception": "Forgetting the negative sign in E = −dV/dr"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The electric potential at the equatorial point of a dipole (on the perpendicular bisector of the dipole) is maximum.", "explanation": "FALSE. The potential at the equatorial point of a dipole is zero, not maximum. At any point on the perpendicular bisector, the distances from both charges are equal, so V = kq/r + k(−q)/r = 0. The maximum potential occurs on the axial line near the positive charge.", "correct_answer": "B", "concept_tags": ["dipole-potential", "equatorial-point", "zero-potential"], "payload": {"question_id": "cuet-phy-elec-potential-33", "subtopic": "Potential due to a dipole", "topic_name": "Electric Potential", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The potential at the equatorial point is exactly zero because equal and opposite charges contribute equally. V = k(+q)/r + k(−q)/r = 0.", "misconception": "Confusing the equatorial point''s zero potential with maximum potential"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-potential", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Two equipotential surfaces can intersect each other.", "explanation": "This statement is FALSE. If two equipotential surfaces intersected, the point of intersection would have two different values of potential simultaneously, which is physically impossible since potential is a single-valued function of position.", "correct_answer": "B", "concept_tags": ["equipotential surface", "properties", "intersection"], "payload": {"question_id": "cuet-phy-elec-potential-34", "subtopic": "Electric Potential and Potential Energy", "topic_name": "Electric Potential", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If two equipotential surfaces intersected, the point of intersection would have two different potential values, which violates the definition of a scalar field.", "misconception": "Thinking equipotential surfaces can cross like field lines in some cases"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b04');

